    target: GcmsMigrationServer; sources: GcmsMigrationServer[]; issues: string[]; domain_conflicts: string[]; can_start: boolean;
  };
  type GcmsMigrationSnapshot = {
    id: string; target_id: string; source_id: string; source_name: string; version: string; bytes: number;
    instance_path: string; port: number; source_base_url: string; source_redirect_domain: string;
    base_url: string; redirect_domain: string; access_configured: boolean; service_name: string;
    https_ok: boolean; cloudflare_proxy_applicable: boolean; cloudflare_proxied: boolean; cloudflare_proxy_error: string;
    service_installed: boolean; service_enabled: boolean; running: boolean;
    remote_state: 'running' | 'stopped' | 'missing' | 'residual' | 'unreachable' | 'unknown'; remote_detail: string;
    created_at: number; updated_at: number; last_error: string;
  };
  type GcmsMigrationStageResult = { target_id: string; snapshots: GcmsMigrationSnapshot[]; failures: string[]; backup_path: string };
  type GcmsMigrationSourceOption = {
    value: string; label: string; sub: string; disabled?: boolean; connectionId: string;
    instanceKind: 'main' | 'migration'; serverName: string; instanceName: string;
    version: string; port: number; running: boolean; domain: string;
  };
  type GcmsMigrationSiteDomain = {
    id: number; scheme: string; host: string; is_primary: boolean; redirect_to_primary: boolean;
    enabled: boolean; access_configured: boolean; web_provider: string;
  };
  type GcmsMigrationSiteCloudflare = {
    configured: boolean; published: boolean; status: string; deploy_mode: string; primary_domain: string;
    worker_name: string; pages_project_name: string; account_name: string; zone_name: string; token_set: boolean;
  };
  type GcmsMigrationSite = {
    id: number; slug: string; name: string; status: string; is_default: boolean; data_present: boolean;
    uploads_present: boolean; deployment: 'main' | 'cloudflare' | 'local' | 'unbound';
    domains: GcmsMigrationSiteDomain[]; cloudflare: GcmsMigrationSiteCloudflare;
  };
  type GcmsChildMigrationView = {
    instanceId: string; loading: boolean; error: string; sites: GcmsMigrationSite[];
  };
  type GcmsAccessWizard = {
    connId: string; connName: string; domain: string; redirectDomain: string; checking: boolean; creatingDns: boolean; configuring: boolean;
    instancePath?: string; instancePort?: number; migrationInstanceId?: string; childSiteId?: number; childSiteName?: string;
    childDomainId?: number; childDomainKind?: 'primary' | 'alias' | 'redirect'; childPrimaryDomain?: string;
    intent: 'configure' | 'migrate_source' | 'migrate_child' | 'bind_new' | 'change' | 'https_proxy';
    activeStep: number; detailsOpen: boolean; redirectOpen: boolean;
    check: GcmsAccessCheck | null; result: GcmsAccessApplyResult | null;
    error: string; notice: string; phase: string; log: string;
  };
  const emptyGcmsServer = (): GcmsServerView => ({ checking: false, status: null, accessHealth: null, error: '', phase: '', log: '' });
  const sshServers = $derived(conns.filter((c) => c.kind === 'ssh'));
  let gcmsServers = $state<Record<string, GcmsServerView>>({});
  let gcmsAccessHealthChecking = $state<Record<string, boolean>>({});
  let gcmsInstalling = $state<Record<string, number>>({});
  let gcmsAssistantImporting = $state<Record<string, boolean>>({});
  let gcmsUpdates = $state<Record<string, GcmsRemoteUpdateInfo>>({});
  let gcmsUpdateChecking = $state<Record<string, boolean>>({});
  let gcmsUpdateErrors = $state<Record<string, string>>({});
  let gcmsUpgrading = $state<Record<string, number>>({});
  let gcmsInstallClock = $state(Date.now());
  let gcmsPasswordEditor = $state<GcmsPasswordEditor | null>(null);
  let gcmsAccess = $state<GcmsAccessWizard | null>(null);
  let gcmsChildMigration = $state<GcmsChildMigrationView | null>(null);
  let gcmsCardMenu = $state<null | { connId: string; x: number; y: number; anchorTop: number; anchorBottom: number; anchorRight: number; ready: boolean }>(null);
  let gcmsCardMenuEl = $state<HTMLDivElement | null>(null);
  let gcmsInstanceMenu = $state<null | { instanceId: string; x: number; y: number; anchorTop: number; anchorBottom: number; anchorRight: number; ready: boolean }>(null);
  let gcmsInstanceMenuEl = $state<HTMLDivElement | null>(null);
  let gcmsMigrationOpen = $state(false);
  let gcmsMigrationTarget = $state('');
  let gcmsMigrationSourcePick = $state('');
  let gcmsMigrationSources = $state<string[]>([]);
  let gcmsMigrationChecking = $state(false);
  let gcmsMigrationStaging = $state(false);
  let gcmsMigrationPhase = $state('');
  let gcmsMigrationStage = $state<GcmsMigrationStageResult | null>(null);
  let gcmsMigrationError = $state('');
  let gcmsMigrationPreflight = $state<GcmsMigrationPreflight | null>(null);
  let gcmsMigrationInstances = $state<GcmsMigrationSnapshot[]>([]);
  let gcmsMigrationInstancesLoading = $state(false);
  let gcmsMigrationHealthChecking = $state<Record<string, boolean>>({});
  let gcmsMigrationRestarting = $state('');
  let gcmsMigrationStopping = $state('');
  let gcmsMigrationRefreshing = $state('');
  let gcmsMigrationRemoving = $state('');
  let gcmsServiceActions = $state<Record<string, 'restart' | 'stop'>>({});
  let gcmsMigrationProgress = $state<GcmsMigrationProgress | null>(null);
  let gcmsMigrationLog = $state('');
  let gcmsMigrationBodyEl = $state<HTMLDivElement | null>(null);
  let gcmsMigrationLogEl = $state<HTMLPreElement | null>(null);
  let gcmsMigrationFollow = $state(true);
  const gcmsChecking = $derived(Object.values(gcmsServers).some((s) => s.checking));

  function gcmsMigrationRemoteState(instance: GcmsMigrationSnapshot): GcmsMigrationSnapshot['remote_state'] {
    if (['running', 'stopped', 'missing', 'residual', 'unreachable'].includes(instance.remote_state)) return instance.remote_state;
    return 'unknown';
  }
  function gcmsMigrationRemoteReady(instance: GcmsMigrationSnapshot): boolean {
    return ['running', 'stopped'].includes(gcmsMigrationRemoteState(instance));
  }
  function gcmsMigrationRemoteLabel(instance: GcmsMigrationSnapshot): string {
    switch (gcmsMigrationRemoteState(instance)) {
      case 'running': return '运行中';
      case 'stopped': return '已停止';
      case 'missing': return '已删除';
      case 'residual': return '有残留';
      case 'unreachable': return '待确认';
      default: return '检测中';
    }
  }
  function gcmsMigrationInstanceBusy(instanceId: string): boolean {
    return [gcmsMigrationRestarting, gcmsMigrationStopping, gcmsMigrationRefreshing, gcmsMigrationRemoving].includes(instanceId);
  }

  const gcmsMigrationTargetOptions = $derived(sshServers.map((c) => ({ value: c.id, label: c.remark?.trim() || c.name, sub: `${c.ssh_user}@${c.ssh_host}` })));
  const gcmsMigrationAllSourceOptions = $derived.by(() => {
    const options: GcmsMigrationSourceOption[] = [];
    for (const c of sshServers) {
      const status = gcmsServer(c.id).status;
      const serverName = c.remark?.trim() || c.name;
      options.push({
        value: `main:${c.id}`,
        label: `${serverName} · 主实例`,
        sub: `${c.ssh_user}@${c.ssh_host} · :${status?.port || 8080} · ${status?.installed ? `GCMS ${status.version || '版本未知'}` : '未安装 GCMS'}`,
        disabled: !status?.installed,
        connectionId: c.id,
        instanceKind: 'main',
        serverName,
        instanceName: serverName,
        version: status?.version || '',
        port: status?.port || 8080,
        running: !!status?.running,
        domain: domainFromUrl(status?.base_url || ''),
      });
    }
    for (const instance of gcmsMigrationInstances) {
      const c = sshServers.find((item) => item.id === instance.target_id);
      if (!c) continue;
      const serverName = c.remark?.trim() || c.name;
      const domain = domainFromUrl(instance.base_url || instance.source_base_url);
      options.push({
        value: `instance:${instance.id}`,
        label: `${instance.source_name || domain || '迁移实例'} · 迁移实例`,
        sub: `${serverName} · :${instance.port} · GCMS ${instance.version || '版本未知'}`,
        disabled: !instance.instance_path || !gcmsMigrationRemoteReady(instance),
        connectionId: instance.target_id,
        instanceKind: 'migration',
        serverName,
        instanceName: instance.source_name || domain || '迁移实例',
        version: instance.version,
        port: instance.port,
        running: instance.running,
        domain,
      });
    }
    return options;
  });
  const gcmsMigrationSourceOptions = $derived(gcmsMigrationAllSourceOptions.filter((option) =>
    option.connectionId !== gcmsMigrationTarget && !gcmsMigrationSources.includes(option.value)));
  function gcmsMigrationSourceOption(id: string): GcmsMigrationSourceOption | undefined {
    return gcmsMigrationAllSourceOptions.find((option) => option.value === id);
  }
  function changeGcmsMigrationTarget() {
    gcmsMigrationSourcePick = '';
    gcmsMigrationSources = gcmsMigrationSources.filter((id) => gcmsMigrationSourceOption(id)?.connectionId !== gcmsMigrationTarget);
    gcmsMigrationError = '';
    gcmsMigrationPreflight = null;
  }

  async function loadGcmsMigrationInstances() {
    if (gcmsMigrationInstancesLoading) return;
    gcmsMigrationInstancesLoading = true;
    try {
      const instances = await invoke<GcmsMigrationSnapshot[]>('gcms_remote_migration_instances');
      gcmsMigrationInstances = instances;
      const pending = instances.filter(gcmsMigrationAccessNeedsRefresh);
      if (pending.length) void refreshGcmsMigrationAccessHealthBatch(pending);
    } catch (e) {
      gcmsMigrationError = String(e);
    } finally {
      gcmsMigrationInstancesLoading = false;
    }
  }

  function gcmsMigrationAccessNeedsRefresh(instance: GcmsMigrationSnapshot): boolean {
    return gcmsMigrationRemoteReady(instance)
      && instance.access_configured
      && !!domainFromUrl(instance.base_url)
      && !instance.https_ok;
  }

  async function refreshGcmsMigrationAccessHealthBatch(instances: GcmsMigrationSnapshot[]) {
    for (const instance of instances) await refreshGcmsMigrationAccessHealth(instance);
  }

  async function refreshGcmsMigrationAccessHealth(instance: GcmsMigrationSnapshot) {
    if (gcmsMigrationHealthChecking[instance.id]) return;
    gcmsMigrationHealthChecking = { ...gcmsMigrationHealthChecking, [instance.id]: true };
    try {
      const refreshed = await invoke<GcmsMigrationSnapshot>('gcms_remote_migration_refresh_access', { instanceId: instance.id });
      gcmsMigrationInstances = gcmsMigrationInstances.map((item) => item.id === refreshed.id ? refreshed : item);
      if (gcmsMigrationStage) gcmsMigrationStage = { ...gcmsMigrationStage, snapshots: gcmsMigrationStage.snapshots.map((item) => item.id === refreshed.id ? refreshed : item) };
    } catch {
      // 状态回填是后台只读增强；失败时保留灰色未知态，用户仍可点击图标进入完整检测。
    } finally {
      const next = { ...gcmsMigrationHealthChecking };
      delete next[instance.id];
      gcmsMigrationHealthChecking = next;
    }
  }

  async function appendGcmsMigrationLog(text: string) {
    if (!text.trim()) return;
    const next = [gcmsMigrationLog, text].filter(Boolean).join('\n');
    gcmsMigrationLog = next.length > 50_000 ? next.slice(-50_000) : next;
    await tick();
    if (gcmsMigrationLogEl) gcmsMigrationLogEl.scrollTop = gcmsMigrationLogEl.scrollHeight;
    await scrollGcmsMigrationToLatest();
  }

  function handleGcmsMigrationBodyScroll() {
    if (!gcmsMigrationBodyEl || !gcmsMigrationStaging) return;
    const distance = gcmsMigrationBodyEl.scrollHeight - gcmsMigrationBodyEl.scrollTop - gcmsMigrationBodyEl.clientHeight;
    gcmsMigrationFollow = distance <= 72;
  }

  async function scrollGcmsMigrationToLatest(force = false) {
    await tick();
    if (!gcmsMigrationBodyEl || (!force && !gcmsMigrationFollow)) return;
    gcmsMigrationFollow = true;
    gcmsMigrationBodyEl.scrollTop = gcmsMigrationBodyEl.scrollHeight;
  }

  function gcmsMigrationPercent(): number {
    if (!gcmsMigrationProgress?.total) return 0;
    const transferFraction = gcmsMigrationProgress.bytes_total > 0
      ? Math.min(1, gcmsMigrationProgress.bytes_current / gcmsMigrationProgress.bytes_total)
      : 0;
    // 流式传输合并了旧的“下载到本机 + 上传到目标”两个阶段，因此占两个进度刻度。
    const effectiveCurrent = gcmsMigrationProgress.current + transferFraction * 2;
    return Math.max(0, Math.min(100, Math.round((effectiveCurrent / gcmsMigrationProgress.total) * 100)));
  }

  function formatGcmsTransferBytes(value: number): string {
    if (!Number.isFinite(value) || value <= 0) return '0 B';
    const units = ['B', 'KB', 'MB', 'GB', 'TB'];
    const unit = Math.min(units.length - 1, Math.floor(Math.log(value) / Math.log(1024)));
    const scaled = value / (1024 ** unit);
    return `${scaled >= 100 || unit === 0 ? scaled.toFixed(0) : scaled.toFixed(1)} ${units[unit]}`;
  }

  function openGcmsMigration(targetId = '') {
    gcmsCardMenu = null;
    gcmsInstanceMenu = null;
    gcmsMigrationOpen = true;
    gcmsMigrationTarget = targetId || sshServers.find((c) => gcmsServer(c.id).status?.installed)?.id || sshServers[0]?.id || '';
    gcmsMigrationSourcePick = '';
    gcmsMigrationSources = [];
    gcmsMigrationChecking = false;
    gcmsMigrationStaging = false;
    gcmsMigrationPhase = '';
    gcmsMigrationStage = null;
    gcmsMigrationError = '';
    gcmsMigrationPreflight = null;
    gcmsMigrationProgress = null;
    gcmsMigrationLog = '';
    gcmsMigrationFollow = true;
    void loadGcmsMigrationInstances();
  }
  function closeGcmsMigration() {
    if (gcmsMigrationChecking || gcmsMigrationStaging) return;
    gcmsMigrationOpen = false;
    gcmsMigrationSourcePick = '';
    gcmsMigrationPreflight = null;
    gcmsMigrationError = '';
  }
  async function stageGcmsMigration() {
    if (gcmsMigrationChecking || gcmsMigrationStaging) return;
    if (!gcmsMigrationPreflight?.can_start) { gcmsMigrationError = '请先完成预检并处理所有问题'; return; }
    gcmsMigrationStaging = true; gcmsMigrationError = ''; gcmsMigrationPhase = '准备原始快照…'; gcmsMigrationStage = null;
    gcmsMigrationProgress = null; gcmsMigrationLog = ''; gcmsMigrationFollow = true;
    await scrollGcmsMigrationToLatest(true);
    const onEvent = new Channel<GcmsInstallEvent>();
    onEvent.onmessage = (event) => {
      if (event.type === 'phase') {
        gcmsMigrationPhase = event.message;
        void scrollGcmsMigrationToLatest();
      }
      else if (event.type === 'progress') {
        gcmsMigrationPhase = event.message;
        gcmsMigrationProgress = event;
        void scrollGcmsMigrationToLatest();
      } else if (event.type === 'log') void appendGcmsMigrationLog(event.text);
    };
    try {
      gcmsMigrationStage = await invoke<GcmsMigrationStageResult>('gcms_remote_migration_stage', {
        targetId: gcmsMigrationTarget, sourceIds: gcmsMigrationSources, onEvent,
      });
      gcmsMigrationInstances = gcmsMigrationStage.snapshots.length
        ? [...gcmsMigrationStage.snapshots, ...gcmsMigrationInstances.filter((item) => !gcmsMigrationStage?.snapshots.some((snapshot) => snapshot.id === item.id))]
        : gcmsMigrationInstances;
      gcmsMigrationPhase = gcmsMigrationStage.failures.length ? '迁移已完成，但有部分实例需要处理' : '独立实例已迁移并登记';
      if (!gcmsMigrationStage.failures.length && gcmsMigrationStage.snapshots.length) {
        await refreshGcmsServers();
        gcmsMigrationOpen = false;
        gcmsInstallOpen = true;
        gcmsAccess = null;
        say(`迁移完成，已新增 ${gcmsMigrationStage.snapshots.length} 个独立实例`);
      }
    } catch (e) { gcmsMigrationError = String(e); gcmsMigrationPhase = ''; }
    finally { gcmsMigrationStaging = false; }
  }
  async function restartGcmsMigrationInstance(instance: GcmsMigrationSnapshot) {
    if (gcmsMigrationRestarting || gcmsMigrationStopping) return;
    const action = instance.running ? '重启' : '启动';
    gcmsInstanceMenu = null;
    requestVerifiedGcmsPassword({
      title: `${action}迁移实例`,
      message: instance.running
        ? `端口 :${instance.port} 会短暂不可访问；目录、数据和域名配置不会改变。`
        : `将按端口 :${instance.port} 和现有配置启动，不会修改实例数据。`,
      instance: instance.source_name,
    }, {
      connId: instance.target_id,
      instancePath: instance.instance_path,
      migrationInstanceId: instance.id,
    }, async (adminPassword) => {
      gcmsMigrationRestarting = instance.id;
      gcmsMigrationError = '';
      try {
        const refreshed = await invoke<GcmsMigrationSnapshot>('gcms_remote_migration_restart', { instanceId: instance.id, adminPassword });
        gcmsMigrationInstances = gcmsMigrationInstances.map((item) => item.id === refreshed.id ? refreshed : item);
        if (gcmsMigrationStage) gcmsMigrationStage = { ...gcmsMigrationStage, snapshots: gcmsMigrationStage.snapshots.map((item) => item.id === refreshed.id ? refreshed : item) };
        say(`迁移实例已${action}`);
      } catch (e) {
        gcmsMigrationError = String(e);
        throw e;
      } finally {
        gcmsMigrationRestarting = '';
      }
    });
  }
  async function stopGcmsMigrationInstance(instance: GcmsMigrationSnapshot) {
    if (gcmsMigrationRestarting || gcmsMigrationStopping || !instance.running) return;
    gcmsInstanceMenu = null;
    requestVerifiedGcmsPassword({
      title: '关闭实例服务',
      message: `端口 :${instance.port} 的网站与后台将不可访问；目录、数据、域名和开机自启配置都会保留。`,
      instance: instance.source_name,
    }, {
      connId: instance.target_id,
      instancePath: instance.instance_path,
      migrationInstanceId: instance.id,
    }, async (adminPassword) => {
      gcmsMigrationStopping = instance.id;
      gcmsMigrationError = '';
      try {
        const refreshed = await invoke<GcmsMigrationSnapshot>('gcms_remote_migration_stop', { instanceId: instance.id, adminPassword });
        gcmsMigrationInstances = gcmsMigrationInstances.map((item) => item.id === refreshed.id ? refreshed : item);
        if (gcmsMigrationStage) gcmsMigrationStage = { ...gcmsMigrationStage, snapshots: gcmsMigrationStage.snapshots.map((item) => item.id === refreshed.id ? refreshed : item) };
        say('迁移实例服务已关闭');
      } catch (e) {
        gcmsMigrationError = String(e);
        throw e;
      } finally {
        gcmsMigrationStopping = '';
      }
    });
  }
  async function recheckGcmsMigrationInstance(instance: GcmsMigrationSnapshot) {
    if (gcmsMigrationInstanceBusy(instance.id)) return;
    gcmsInstanceMenu = null;
    gcmsMigrationRefreshing = instance.id;
    gcmsMigrationError = '';
    try {
      const instances = await invoke<GcmsMigrationSnapshot[]>('gcms_remote_migration_instances');
      gcmsMigrationInstances = instances;
      const refreshed = instances.find((item) => item.id === instance.id);
      if (!refreshed) {
        say('迁移实例记录已移除');
      } else {
        say(`检测完成：${gcmsMigrationRemoteLabel(refreshed)}`);
      }
    } catch (e) {
      gcmsMigrationError = String(e);
      say(gcmsMigrationError, 'err');
    } finally {
      gcmsMigrationRefreshing = '';
    }
  }
  async function removeGcmsMigrationInstance(instance: GcmsMigrationSnapshot) {
    if (gcmsMigrationInstanceBusy(instance.id)) return;
    const remoteState = gcmsMigrationRemoteState(instance);
    if (remoteState === 'unreachable' || remoteState === 'unknown') {
      say('请先恢复服务器连接并重新检测，Pilot 不会在状态未知时删除实例', 'err');
      return;
    }
    const onlyForget = remoteState === 'missing';
    const actionLabel = onlyForget ? '移除记录' : remoteState === 'residual' ? '清理残留' : '卸载实例';
    if (!onlyForget) {
      gcmsInstanceMenu = null;
      requestVerifiedGcmsPassword({
        title: actionLabel,
        message: '将永久删除该实例的目录、数据、systemd 与 Web 配置。DNS 和 Cloudflare 记录会保留。',
        instance: instance.source_name,
        kind: 'danger',
      }, {
        connId: instance.target_id,
        instancePath: instance.instance_path,
        migrationInstanceId: instance.id,
      }, async (adminPassword) => {
        gcmsMigrationRemoving = instance.id;
        gcmsMigrationError = '';
        try {
          await invoke('gcms_remote_migration_uninstall', { instanceId: instance.id, adminPassword });
          gcmsMigrationInstances = gcmsMigrationInstances.filter((item) => item.id !== instance.id);
          gcmsMigrationSources = gcmsMigrationSources.filter((item) => item !== `instance:${instance.id}`);
          if (gcmsMigrationStage) gcmsMigrationStage = { ...gcmsMigrationStage, snapshots: gcmsMigrationStage.snapshots.filter((item) => item.id !== instance.id) };
          say(`${actionLabel}完成，DNS 与 Cloudflare 记录已保留`);
        } catch (e) {
          gcmsMigrationError = String(e);
          void loadGcmsMigrationInstances();
          throw e;
        } finally {
          gcmsMigrationRemoving = '';
        }
      });
      return;
    }
    const yes = await confirmDialog(
      `移除迁移实例「${instance.source_name}」的本地记录？\n\nPilot 已再次确认远端没有实例目录、systemd 服务或托管的 Web 配置。此操作只清除 Pilot 中的登记。`,
      { title: actionLabel, kind: 'danger', confirmText: actionLabel },
    );
    if (!yes) return;
    gcmsInstanceMenu = null;
    gcmsMigrationRemoving = instance.id;
    gcmsMigrationError = '';
    try {
      await invoke('gcms_remote_migration_forget', { instanceId: instance.id });
      gcmsMigrationInstances = gcmsMigrationInstances.filter((item) => item.id !== instance.id);
      gcmsMigrationSources = gcmsMigrationSources.filter((item) => item !== `instance:${instance.id}`);
      if (gcmsMigrationStage) gcmsMigrationStage = { ...gcmsMigrationStage, snapshots: gcmsMigrationStage.snapshots.filter((item) => item.id !== instance.id) };
      say('迁移实例记录已移除');
    } catch (e) {
      gcmsMigrationError = String(e);
      say(gcmsMigrationError, 'err');
      void loadGcmsMigrationInstances();
    } finally {
      gcmsMigrationRemoving = '';
    }
  }
  function addGcmsMigrationSource(id: string) {
    const option = gcmsMigrationSourceOption(id);
    if (option && !option.disabled && option.connectionId !== gcmsMigrationTarget && !gcmsMigrationSources.includes(id)) {
      gcmsMigrationSources = [...gcmsMigrationSources, id];
    }
    gcmsMigrationSourcePick = '';
    gcmsMigrationError = '';
    gcmsMigrationPreflight = null;
  }
  function removeGcmsMigrationSource(id: string) {
    gcmsMigrationSources = gcmsMigrationSources.filter((item) => item !== id);
    gcmsMigrationError = '';
    gcmsMigrationPreflight = null;
  }
  async function checkGcmsMigration() {
    if (gcmsMigrationChecking) return;
    if (!gcmsMigrationTarget) { gcmsMigrationError = '请选择目标服务器'; return; }
    if (!gcmsMigrationSources.length) { gcmsMigrationError = '至少选择一个源实例'; return; }
    gcmsMigrationChecking = true; gcmsMigrationError = ''; gcmsMigrationPreflight = null;
    try {
      gcmsMigrationPreflight = await invoke<GcmsMigrationPreflight>('gcms_remote_migration_preflight', {
        targetId: gcmsMigrationTarget, sourceIds: gcmsMigrationSources,
      });
    } catch (e) { gcmsMigrationError = String(e); }
    finally {
      gcmsMigrationChecking = false;
      await scrollGcmsMigrationToLatest(true);
    }
  }

  function gcmsServer(id: string): GcmsServerView { return gcmsServers[id] ?? emptyGcmsServer(); }
  function gcmsPilotAssistant(sourceId: string): Connection | undefined {
    return conns.find((connection) => connection.kind === 'gcms' && connection.source_ssh_id === sourceId);
  }
  function connectionDisplayName(connection: Connection): string {
    const assistantDomain = connection.kind === 'gcms' && connection.source_ssh_id
      ? domainFromUrl(connection.api_base)
      : '';
    return assistantDomain || connection.name;
  }
  function gcmsAssistantImportTip(status: GcmsRemoteStatus, imported: boolean): string {
    if (!status.running) return '请先启动 GCMS 服务';
    if (!gcmsHttpsConfigured(status)) return imported
      ? '访问域名不可用；已导入记录会保留，修复后可继续同步'
      : '请先设置访问域名并启用 HTTPS';
    if (!status.assistant_import_supported) return '请先升级 GCMS，再导入 Pilot 运营助手';
    return imported
      ? '同步最新技能包与全站运营权限；已有对话会保留'
      : '创建全站运营密钥并导入当前 Pilot；密钥只保存在系统钥匙串';
  }
  async function importGcmsPilotAssistant(c: Connection, status: GcmsRemoteStatus) {
    if (gcmsAssistantImporting[c.id]) return;
    if (!status.running) { say('请先启动 GCMS 服务，再导入 Pilot 运营助手', 'err'); return; }
    if (!gcmsHttpsConfigured(status)) { say('请先设置访问域名并启用 HTTPS，再导入 Pilot 运营助手', 'err'); return; }
    if (!status.assistant_import_supported) { say('当前 GCMS 版本尚不支持一键导入，请先升级 GCMS', 'err'); return; }
    const existed = !!gcmsPilotAssistant(c.id);
    gcmsAssistantImporting = { ...gcmsAssistantImporting, [c.id]: true };
    try {
      const outcome = await invoke<ImportOutcome>('gcms_remote_import_pilot_assistant', { connId: c.id });
      if (outcome.status === 'needs_key') throw new Error('GCMS 未能签发 Pilot 运营助手密钥，请重新检测后再试');
      delete packUpdates[outcome.connection.id];
      delete packUpdateChecks[outcome.connection.id];
      await refreshConns();
      const assistantName = connectionDisplayName(outcome.connection);
      say(existed || outcome.status === 'upgraded'
        ? `「${assistantName}」已更新，原有对话全部保留`
        : `「${assistantName}」已导入当前 Pilot`);
    } catch (e) {
      say(String(e), 'err');
    } finally {
      const next = { ...gcmsAssistantImporting };
      delete next[c.id];
      gcmsAssistantImporting = next;
    }
  }
  async function checkRemoteGcmsUpdate(connId: string, silent = false, force = false): Promise<GcmsRemoteUpdateInfo | null> {
    if (gcmsUpdateChecking[connId] || gcmsUpgrading[connId]) return gcmsUpdates[connId] ?? null;
    if (force) {
      const updates = { ...gcmsUpdates };
      delete updates[connId];
      gcmsUpdates = updates;
    }
    if (!force && gcmsUpdates[connId]) return gcmsUpdates[connId];
    const status = gcmsServer(connId).status;
    if (!status?.installed) return null;
    if (!status.update_supported) {
      const message = '当前 GCMS 安装不支持在线升级，请先使用标准安装包更新';
      gcmsUpdateErrors = { ...gcmsUpdateErrors, [connId]: message };
      if (!silent) say(message, 'err');
      return null;
    }
    gcmsUpdateChecking = { ...gcmsUpdateChecking, [connId]: true };
    try {
      const info = await invoke<GcmsRemoteUpdateInfo>('gcms_remote_check_update', { connId });
      gcmsUpdates = { ...gcmsUpdates, [connId]: info };
      const errors = { ...gcmsUpdateErrors };
      delete errors[connId];
      gcmsUpdateErrors = errors;
      if (!silent) say(info.has_update ? `发现 GCMS 新版本 ${info.latest}` : `GCMS ${info.current || status.version} 已是最新版本`);
      return info;
    } catch (e) {
      const message = String(e);
      gcmsUpdateErrors = { ...gcmsUpdateErrors, [connId]: message };
      if (!silent) say(message, 'err');
      return null;
    } finally {
      const next = { ...gcmsUpdateChecking };
      delete next[connId];
      gcmsUpdateChecking = next;
    }
  }
  function sameUpdateVersion(actual: string, expected: string): boolean {
    return actual.trim().replace(/^v/i, '') === expected.trim().replace(/^v/i, '');
  }
  async function upgradeRemoteGcms(
    c: Connection,
    current: GcmsRemoteStatus,
    options: { confirm?: boolean; notify?: boolean; refreshPacks?: boolean } = {},
  ): Promise<UpdateActionResult> {
    const notify = options.notify !== false;
    const shouldConfirm = options.confirm !== false;
    if (gcmsUpgrading[c.id] || gcmsInstalling[c.id]) return { ok: false, message: '该服务器已有操作正在进行' };
    const activePacks = gcmsPacksForServer(c.id).filter((pack) => connectionHasActiveTurn(pack.id));
    if (activePacks.length) {
      const message = `关联连接「${activePacks.map(connectionDisplayName).join('、')}」有对话正在运行，请等本轮结束后再升级 GCMS`;
      if (notify) say(message, 'err');
      return { ok: false, message };
    }
    gcmsCardMenu = null;
    const update = gcmsUpdates[c.id] ?? await checkRemoteGcmsUpdate(c.id, !notify, true);
    if (!update) return { ok: false, message: gcmsUpdateErrors[c.id] || '无法取得 GCMS 更新信息' };
    if (!update.has_update) {
      const message = `GCMS ${update.current || current.version} 已是最新版本`;
      if (notify) say(message);
      return { ok: true, message };
    }
    if (shouldConfirm) {
      const yes = await confirmDialog(
        `将「${c.name}」上的 GCMS 从 ${update.current || current.version || '当前版本'} 升级到 ${update.latest}。\n升级器会校验签名、备份数据库并短暂重启服务；健康检查失败会自动回滚。`,
        { title: '在线升级 GCMS', kind: 'info', confirmText: '开始升级' },
      );
      if (!yes) return { ok: false, message: '已取消升级' };
    }
    gcmsUpgrading = { ...gcmsUpgrading, [c.id]: Date.now() };
    patchGcmsServer(c.id, { status: current, error: '', phase: `准备升级到 ${update.latest}…`, log: '' });
    const onEvent = new Channel<GcmsInstallEvent>();
    onEvent.onmessage = (event) => {
      if (event.type === 'phase') patchGcmsServer(c.id, { phase: event.message });
      else if (event.type === 'log') {
        const log = gcmsServer(c.id).log;
        patchGcmsServer(c.id, { log: [log, event.text].filter(Boolean).join('\n') });
      }
    };
    let observed = current;
    try {
      const status = await invoke<GcmsRemoteStatus>('gcms_remote_upgrade', { connId: c.id, targetVersion: update.latest, onEvent });
      observed = status;
      if (!sameUpdateVersion(status.version, update.latest)) {
        throw new Error(`升级后版本核验失败：期望 ${update.latest}，服务器实际为 ${status.version || '未知'}`);
      }
      patchGcmsServer(c.id, { status, error: '', phase: '升级完成' });
      gcmsUpdates = { ...gcmsUpdates, [c.id]: { current: status.version, latest: update.latest, has_update: false } };
      const errors = { ...gcmsUpdateErrors };
      delete errors[c.id];
      gcmsUpdateErrors = errors;
      const message = `GCMS 已升级到 ${status.version || update.latest}`;
      if (options.refreshPacks !== false) {
        await Promise.all(gcmsPacksForServer(c.id).map((pack) => maybeCheckPackUpdate(pack.id, true, false)));
      }
      if (notify) say(message);
      return { ok: true, message };
    } catch (e) {
      const message = String(e);
      patchGcmsServer(c.id, { status: observed, error: message, phase: '在线升级失败' });
      if (notify) say(message, 'err');
      return { ok: false, message };
    } finally {
      const next = { ...gcmsUpgrading };
      delete next[c.id];
      gcmsUpgrading = next;
    }
  }
  function gcmsDetailsTip(status: GcmsRemoteStatus): string {
    return `安装目录：${status.path || '未知'}`;
  }
  function gcmsAdminUrl(status: GcmsRemoteStatus): string {
    const raw = status.base_url.trim();
    if (!/^https?:\/\//i.test(raw)) return '';
    try {
      const url = new URL(raw);
      const path = url.pathname.replace(/\/+$/, '');
      url.pathname = path.toLowerCase().endsWith('/admin') ? path : `${path}/admin`;
      url.search = '';
      url.hash = '';
      return url.toString();
    } catch { return ''; }
  }
  function gcmsHttpsConfigured(status: Pick<GcmsRemoteStatus, 'base_url'>): boolean {
    return /^https:\/\//i.test(status.base_url.trim());
  }
  function openGcmsAddress(status: GcmsRemoteStatus) {
    const url = gcmsAdminUrl(status);
    if (url) void openUrl(url);
  }
  function gcmsPasswordUrl(status: GcmsRemoteStatus): string {
    const admin = gcmsAdminUrl(status);
    if (!admin) return '';
    try {
      const url = new URL(admin);
      url.pathname = '/admin/security';
      url.search = '';
      url.hash = '';
      return url.toString();
    } catch { return ''; }
  }
  function openGcmsPasswordPage(status: GcmsRemoteStatus) {
    const url = gcmsPasswordUrl(status);
    if (url) void openUrl(url);
  }
  function closeGcmsPasswordEditor() {
    if (gcmsPasswordEditor?.saving) return;
    if (gcmsPasswordEditor) {
      gcmsPasswordEditor.password = '';
      gcmsPasswordEditor.confirm = '';
    }
    gcmsPasswordEditor = null;
  }
  function openGcmsPasswordEditor(c: Connection, status: GcmsRemoteStatus, justInstalled = false) {
    if (gcmsPasswordEditor?.saving) return;
    gcmsCardMenu = null;
    if (status.password_status === 'changed') {
      say('后台密码已修改，请在 GCMS 后台继续管理', 'err');
      return;
    }
    if (status.password_status !== 'default') {
      say('无法确认后台仍在使用初始密码，请重新检测后再试', 'err');
      return;
    }
    if (!status.password_change_supported) {
      const url = gcmsPasswordUrl(status);
      if (url) openGcmsPasswordPage(status);
      else say('当前 GCMS 版本需升级后才能在 Pilot 中设置初始密码', 'err');
      return;
    }
    closeGcmsPasswordEditor();
    gcmsPasswordEditor = {
      connId: c.id, serverName: c.name, password: '', confirm: '',
      visible: false, saving: false, error: '', justInstalled,
    };
    requestAnimationFrame(() => {
      document.querySelector('[data-gcms-password-editor]')?.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    });
  }
  function updateGcmsPasswordEditor(patch: Partial<GcmsPasswordEditor>) {
    if (gcmsPasswordEditor) gcmsPasswordEditor = { ...gcmsPasswordEditor, ...patch };
  }
  function generateGcmsPassword() {
    if (!gcmsPasswordEditor || gcmsPasswordEditor.saving) return;
    const alphabet = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%_-';
    const chars = ['A', 'a', '7', '!'];
    const random = new Uint32Array(40);
    crypto.getRandomValues(random);
    for (let i = 0; i < 16; i += 1) chars.push(alphabet[random[i] % alphabet.length]);
    for (let i = chars.length - 1; i > 0; i -= 1) {
      const j = random[16 + (chars.length - 1 - i)] % (i + 1);
      [chars[i], chars[j]] = [chars[j], chars[i]];
    }
    const password = chars.join('');
    updateGcmsPasswordEditor({ password, confirm: password, visible: true, error: '' });
  }
  function validateGcmsPassword(password: string, confirm: string): string {
    if ([...password].length < 8) return '新密码至少需要 8 个字符';
    if (new TextEncoder().encode(password).length > 72) return '新密码过长，最多 72 个英文字符（中文等字符占用更多长度）';
    if (/[\0\r\n]/.test(password)) return '新密码不能包含换行或空字符';
    if (password === 'admin123') return '不能继续使用默认密码 admin123';
    if (password !== confirm) return '两次输入的密码不一致';
    return '';
  }
  async function saveGcmsAdminPassword(c: Connection) {
    const editor = gcmsPasswordEditor;
    if (!editor || editor.connId !== c.id || editor.saving) return;
    const error = validateGcmsPassword(editor.password, editor.confirm);
    if (error) { updateGcmsPasswordEditor({ error }); return; }
    updateGcmsPasswordEditor({ saving: true, error: '' });
    try {
      const status = await invoke<GcmsRemoteStatus>('gcms_remote_set_admin_password', {
        connId: c.id,
        password: editor.password,
      });
      patchGcmsServer(c.id, { status, error: '', phase: '' });
      if (gcmsPasswordEditor?.connId === c.id) {
        gcmsPasswordEditor.password = '';
        gcmsPasswordEditor.confirm = '';
        gcmsPasswordEditor = null;
      }
      say(`「${c.name}」的 GCMS 后台密码已更新，旧登录会话已退出`, 'ok');
    } catch (e) {
      const message = String(e);
      if (message.includes('仅支持设置首次安装的初始密码') || message.includes('后台密码已修改')) {
        if (gcmsPasswordEditor?.connId === c.id) {
          gcmsPasswordEditor.password = '';
          gcmsPasswordEditor.confirm = '';
          gcmsPasswordEditor = null;
        }
        await probeRemoteGcms(c.id);
        say('后台密码已在 GCMS 中修改，Pilot 未覆盖现有密码', 'ok');
        return;
      }
      if (gcmsPasswordEditor?.connId === c.id) {
        updateGcmsPasswordEditor({ saving: false, error: message });
      }
    }
  }
  function closeGcmsInstaller() {
    if (gcmsAccess?.creatingDns || gcmsAccess?.configuring || gcmsPasswordEditor?.saving) return;
    gcmsCardMenu = null;
    gcmsInstanceMenu = null;
    gcmsAccess = null;
    gcmsChildMigration = null;
    closeGcmsPasswordEditor();
    gcmsInstallOpen = false;
  }
  function closeGcmsCurrentLayer() {
    if (gcmsAccess?.creatingDns || gcmsAccess?.configuring || gcmsPasswordEditor?.saving) return;
    if (gcmsAccess) {
      gcmsCardMenu = null;
      gcmsInstanceMenu = null;
      gcmsAccess = null;
      return;
    }
    if (gcmsChildMigration) {
      gcmsChildMigration = null;
      return;
    }
    closeGcmsInstaller();
  }
  function domainFromUrl(url: string): string {
    try { return /^https?:\/\//i.test(url) ? new URL(url).hostname : ''; }
    catch { return ''; }
  }
  function openGcmsAccess(
    c: Connection,
    status: GcmsRemoteStatus,
    instance?: {
      id: string; path: string; port: number; domain?: string; redirectDomain?: string;
      intent?: GcmsAccessWizard['intent']; childSiteId?: number; childSiteName?: string;
      childDomainId?: number; childDomainKind?: GcmsAccessWizard['childDomainKind']; childPrimaryDomain?: string;
    },
    intentOverride?: GcmsAccessWizard['intent'],
  ) {
    gcmsCardMenu = null;
    gcmsInstanceMenu = null;
    gcmsAccess = {
      connId: c.id, connName: c.name, domain: instance?.domain || domainFromUrl(status.base_url), redirectDomain: instance ? instance.redirectDomain || '' : status.redirect_domain || '', checking: false, creatingDns: false, configuring: false,
      instancePath: instance?.path, instancePort: instance?.port, migrationInstanceId: instance?.id,
      childSiteId: instance?.childSiteId, childSiteName: instance?.childSiteName,
      childDomainId: instance?.childDomainId, childDomainKind: instance?.childDomainKind, childPrimaryDomain: instance?.childPrimaryDomain,
      intent: intentOverride || instance?.intent || 'configure',
      activeStep: 1, detailsOpen: false, redirectOpen: false,
      check: null, result: null, error: '', notice: '', phase: '', log: '',
    };
  }
  function openGcmsMigrationDomain(snapshot: GcmsMigrationSnapshot, mode: 'current' | 'source' | 'new' | 'https_proxy' = snapshot.access_configured ? 'current' : 'source') {
    const target = sshServers.find((item) => item.id === snapshot.target_id);
    if (!target) {
      gcmsMigrationError = '对应的目标 SSH 连接已经不存在。';
      return;
    }
    const selectedBaseUrl = mode === 'current' || mode === 'https_proxy' ? snapshot.base_url : mode === 'source' ? snapshot.source_base_url : '';
    const selectedRedirectDomain = mode === 'current' || mode === 'https_proxy' ? snapshot.redirect_domain : mode === 'source' ? snapshot.source_redirect_domain : '';
    const status = gcmsServer(target.id).status ?? {
      installed: true, version: snapshot.version, path: snapshot.instance_path, running: snapshot.running,
      port: snapshot.port,
      base_url: selectedBaseUrl, redirect_domain: selectedRedirectDomain,
      password_status: 'unknown' as const, admin_user: '', password_change_supported: false,
    };
    gcmsMigrationOpen = false;
    gcmsChildMigration = null;
    gcmsInstallOpen = true;
    openGcmsAccess(target, status, {
      id: snapshot.id,
      path: snapshot.instance_path,
      port: snapshot.port,
      domain: domainFromUrl(selectedBaseUrl),
      redirectDomain: selectedRedirectDomain,
      intent: mode === 'source' ? 'migrate_source' : mode === 'new' ? 'bind_new' : mode === 'https_proxy' ? 'https_proxy' : 'change',
    });
  }

  function gcmsChildPrimaryDomain(site: GcmsMigrationSite): GcmsMigrationSiteDomain | undefined {
    const enabled = site.domains.filter((domain) => domain.enabled);
    return enabled.find((domain) => domain.is_primary) ?? enabled[0];
  }
  function gcmsChildDomainKind(domain: GcmsMigrationSiteDomain, primary?: GcmsMigrationSiteDomain): 'primary' | 'alias' | 'redirect' {
