      gcmsInstanceMenu = null;
      return;
    }
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    gcmsInstanceMenu = {
      instanceId,
      x: Math.max(8, rect.right - 180),
      y: rect.bottom + 5,
      anchorTop: rect.top,
      anchorBottom: rect.bottom,
      anchorRight: rect.right,
      ready: false,
    };
    await tick();
    if (!gcmsInstanceMenu || gcmsInstanceMenu.instanceId !== instanceId || !gcmsInstanceMenuEl) return;
    const menuRect = gcmsInstanceMenuEl.getBoundingClientRect();
    const x = Math.max(8, Math.min(gcmsInstanceMenu.anchorRight - menuRect.width, window.innerWidth - menuRect.width - 8));
    const below = gcmsInstanceMenu.anchorBottom + 5;
    const y = below + menuRect.height <= window.innerHeight - 8
      ? below
      : Math.max(8, gcmsInstanceMenu.anchorTop - menuRect.height - 5);
    gcmsInstanceMenu = { ...gcmsInstanceMenu, x, y, ready: true };
  }
  $effect(() => {
    if (!gcmsInstanceMenu) return;
    const close = () => (gcmsInstanceMenu = null);
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') gcmsInstanceMenu = null; };
    window.addEventListener('click', close);
    window.addEventListener('keydown', onKey);
    return () => {
      window.removeEventListener('click', close);
      window.removeEventListener('keydown', onKey);
    };
  });
  function patchGcmsAccess(patch: Partial<GcmsAccessWizard>) {
    if (gcmsAccess) gcmsAccess = { ...gcmsAccess, ...patch };
  }
  function setGcmsAccessDomain(value: string) {
    if (!gcmsAccess) return;
    gcmsAccess = { ...gcmsAccess, domain: value, activeStep: 1, detailsOpen: false, check: null, result: null, error: '', notice: '', phase: '', log: '' };
  }
  function setGcmsAccessRedirectDomain(value: string) {
    if (!gcmsAccess) return;
    gcmsAccess = { ...gcmsAccess, redirectDomain: value, activeStep: 1, detailsOpen: false, check: null, result: null, error: '', notice: '', phase: '', log: '' };
  }
  function gcmsRedirectSuggestion(domain: string): string {
    const normalized = domain.trim().replace(/\.$/, '').toLowerCase();
    const labels = normalized.split('.');
    if (labels.length !== 2 || labels.some((label) => !label || label.startsWith('-') || label.endsWith('-') || !/^[a-z0-9-]+$/.test(label))) return '';
    return `www.${normalized}`;
  }
  function gcmsReachedStep(a: GcmsAccessWizard): number {
    if (a.result) return 4;
    if (a.configuring || a.check?.matched) return 3;
    if (a.check) return 2;
    return 1;
  }
  function setGcmsAccessStep(step: number) {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    if (gcmsAccess.intent === 'https_proxy' && gcmsAccess.check?.matched && gcmsAccess.check.caddy && step < 3) return;
    if (step >= 1 && step <= gcmsReachedStep(gcmsAccess)) patchGcmsAccess({ activeStep: step, detailsOpen: false, error: '' });
  }
  function webModeLabel(web: GcmsCaddyPreflight): string {
    if (web.provider === 'nginx' && web.can_auto_configure) return '可自动处理';
    if (web.mode === 'missing') return '待安装';
    if (web.mode === 'standard') return web.running ? '标准 Caddy · 运行中' : '标准 Caddy · 未运行';
    if (web.mode === 'conflict') return '存在冲突';
    if (web.mode === 'custom') return '自定义环境';
    return '不支持自动配置';
  }
  function dnsHostingLabel(hosting: GcmsDnsHosting): string {
    if (hosting.provider === 'cloudflare') return 'Cloudflare';
    if (hosting.provider === 'other') return '其他 DNS 服务商';
    return '暂未识别';
  }
  function cloudflareStatusLabel(check: GcmsCloudflareCheck): string {
    if (check.status === 'matched') return check.proxied ? '橙云已核验' : '仅 DNS 已核验';
    if (check.status === 'connection_required') return '需要连接账号';
    if (check.status === 'connection_selection_required') return '请选择连接';
    if (check.status === 'zone_not_found') return '未找到域名';
    if (check.status === 'permission_error') return '权限不足';
    if (check.status === 'api_error') return '检测失败';
    if (check.status === 'record_missing') return '缺少记录';
    if (check.status === 'origin_mismatch') return '源站不一致';
    if (check.status === 'zone_inactive') return 'Zone 未激活';
    if (check.status === 'ssl_unreadable') return 'SSL 模式未知';
    if (check.status === 'ssl_incompatible') return 'SSL 模式不安全';
    return '记录不支持';
  }
  function cloudflareSslLabel(mode: string): string {
    if (mode === 'strict') return 'Full (strict)';
    if (mode === 'full') return 'Full';
    if (mode === 'flexible') return 'Flexible';
    if (mode === 'off') return 'Off';
    return '未读取';
  }
  function gcmsProxyNeedsPermission(error: string): boolean {
    const detail = error.toLowerCase();
    return detail.includes('zone settings')
      || (detail.includes('ssl/tls') && (detail.includes('cloudflare 403') || detail.includes('unauthorized') || detail.includes('权限')));
  }
  function gcmsProxyNeedsSafeSslMode(error: string): boolean {
    const detail = error.toLowerCase();
    return detail.includes('ssl/tls 当前为') && detail.includes('full');
  }
  function compactCloudflareAccount(accountId: string): string {
    const value = accountId.trim();
    return value.length > 16 ? `${value.slice(0, 7)}…${value.slice(-5)}` : value;
  }
  function cloudflareCandidateLabel(candidate: GcmsCloudflareCandidate): string {
    return candidate.connection_remark.trim() || candidate.connection_name || candidate.key_prefix || 'Cloudflare 连接';
  }
  function cloudflareCandidateSub(candidate: GcmsCloudflareCandidate): string {
    const parts = [];
    if (candidate.connection_remark.trim() && candidate.connection_name) parts.push(candidate.connection_name);
    if (candidate.key_prefix) parts.push(candidate.key_prefix);
    if (candidate.account_id) parts.push(`账号 ${compactCloudflareAccount(candidate.account_id)}`);
    parts.push(candidate.permission_complete ? '核验权限完整' : '还需补充权限');
    return parts.join(' · ');
  }
  function cloudflareCandidateOptions(check: GcmsCloudflareCheck) {
    return (check.candidates ?? []).map((candidate) => ({
      value: candidate.connection_id,
      label: cloudflareCandidateLabel(candidate),
      sub: cloudflareCandidateSub(candidate),
      tip: candidate.detail || undefined,
      tone: candidate.permission_complete ? '' : 'warn',
    }));
  }
  function gcmsAccessRoutes(check: GcmsAccessCheck) {
    return [
      {
        role: gcmsAccess?.intent === 'migrate_child' ? gcmsAccessChildDomainLabel(gcmsAccess) : '主域名', domain: check.domain, matched: check.primary_matched, cloudflare: check.cloudflare,
        hosting: check.hosting, dns_ipv4: check.dns_ipv4, dns_ipv6: check.dns_ipv6, dns_error: check.dns_error,
      },
      ...(check.redirect ? [{
        role: '跳转域名', domain: check.redirect.domain, matched: check.redirect.matched, cloudflare: check.redirect.cloudflare,
        hosting: check.redirect.hosting, dns_ipv4: check.redirect.dns_ipv4, dns_ipv6: check.redirect.dns_ipv6, dns_error: check.redirect.dns_error,
      }] : []),
    ];
  }
  function gcmsActionRoute(check: GcmsAccessCheck) {
    const routes = gcmsAccessRoutes(check);
    return routes.find((route) => !route.matched && route.cloudflare) ?? routes.find((route) => route.cloudflare) ?? routes.find((route) => !route.matched) ?? routes[0];
  }
  function gcmsManualUnmatchedRoute(check: GcmsAccessCheck) {
    return gcmsAccessRoutes(check).find((route) => !route.matched && !route.cloudflare) ?? null;
  }
  function gcmsActionCloudflare(check: GcmsAccessCheck): GcmsCloudflareCheck | null {
    return gcmsActionRoute(check).cloudflare;
  }
  function gcmsProxyCloudflare(check: GcmsAccessCheck | null): GcmsCloudflareCheck | null {
    if (!check) return null;
    const candidates = gcmsAccessRoutes(check).map((route) => route.cloudflare).filter((value): value is GcmsCloudflareCheck => !!value);
    return candidates.find((candidate) => !!candidate.ssl_error)
      ?? candidates.find((candidate) => !candidate.proxied)
      ?? candidates[0]
      ?? null;
  }
  function cloudflareConnectionDisplay(connectionId: string): string {
    const connection = conns.find((item) => item.id === connectionId);
    return connection?.remark?.trim() || connection?.name || 'Cloudflare 连接';
  }
  function hasOtherCloudflareConnections(connectionId: string): boolean {
    return conns.some((connection) => connection.kind === 'cloudflare' && connection.id !== connectionId);
  }
  function gcmsHasCloudflare(check: GcmsAccessCheck): boolean {
    return gcmsAccessRoutes(check).some((route) => !!route.cloudflare);
  }
  function canCreateGcmsCloudflareA(check: GcmsAccessCheck): boolean {
    const unresolved = gcmsAccessRoutes(check).filter((route) => !route.matched);
    return check.server_ipv4.length === 1 && unresolved.length > 0 && unresolved.every((route) => {
      const cf = route.cloudflare;
      return !!cf && cf.status === 'record_missing' && !!cf.connection_id && cf.zone_status === 'active';
    });
  }
  function canCutoverGcmsCloudflare(check: GcmsAccessCheck): boolean {
    if (!gcmsAccess?.migrationInstanceId || check.server_ipv4.length !== 1) return false;
    const unresolved = gcmsAccessRoutes(check).filter((route) => !route.matched);
    return unresolved.length > 0 && unresolved.every((route) => {
      const cf = route.cloudflare;
      return !!cf && cf.status === 'origin_mismatch' && !!cf.connection_id && cf.zone_status === 'active';
    });
  }
  function gcmsCloudflareSummary(check: GcmsAccessCheck): string {
    const cf = gcmsActionCloudflare(check);
    if (check.matched) {
      return check.caddy?.can_auto_configure
        ? check.redirect
          ? '两个域名都已连接。Pilot 将配置 HTTPS 和 301，验证源站后再安全开启 Cloudflare 橙云。'
          : '域名已经连接。Pilot 将配置并验证源站 HTTPS，成功后再安全开启 Cloudflare 橙云。'
        : '域名已经连接到这台服务器，但服务器环境需要处理后才能继续配置 HTTPS。';
    }
    if (canCreateGcmsCloudflareA(check)) return check.redirect
      ? 'Pilot 会先创建缺少的灰云 A 记录，再配置 HTTPS 和 301；源站验证通过后自动开启橙云。'
      : 'Pilot 会先连接域名并配置源站 HTTPS，验证后台正常后自动开启 Cloudflare 橙云。';
    if (canCutoverGcmsCloudflare(check)) return check.redirect
      ? '这是迁移实例。Pilot 可为两个老域名建立 DNS 回滚点，切到新服务器并验证 HTTPS；失败会恢复旧源站。'
      : '这是迁移实例。Pilot 可先建立 DNS 回滚点，再把老域名切到新服务器并验证后台；失败会恢复旧源站。';
    if (gcmsManualUnmatchedRoute(check)) return `${gcmsManualUnmatchedRoute(check)!.role}尚未指向这台服务器，请按高级设置中的记录提示完成 DNS 配置。`;
    if (!cf) return '有域名尚未连接到这台服务器，请按高级设置中的记录提示完成 DNS 配置。';
    if (cf.status === 'connection_required') return '这个域名由 Cloudflare 管理。连接对应账号后，Pilot 就能自动完成后续设置。';
    if (cf.status === 'connection_selection_required') return 'Pilot 找到了多条可能管理这个域名的 Cloudflare 连接。请选择一条，后续 DNS、HTTPS 与橙云都会固定使用它。';
    if (cf.status === 'zone_not_found') return '当前连接的 Cloudflare 账号中没有这个域名，请连接管理该域名的账号。';
    if (cf.status === 'permission_error' || cf.status === 'ssl_unreadable') return `当前使用「${cloudflareConnectionDisplay(cf.connection_id)}」，它缺少核验所需权限。更新这一条连接即可，不会影响其他 Token。`;
    if (cf.status === 'origin_mismatch') return '该域名当前指向另一台服务器。普通接入不会覆盖；只有已登记迁移实例可在明确确认后安全切换。';
    if (cf.status === 'unsupported_record') return '检测到不能安全自动修改的 DNS 记录，Pilot 已停止操作以避免覆盖现有配置。';
    if (cf.status === 'zone_inactive') return '这个 Cloudflare Zone 尚未激活，请先在 Cloudflare 完成域名托管。';
    if (cf.status === 'ssl_incompatible') return '橙云已开启，但当前 SSL/TLS 模式不适合源站 HTTPS，请先调整 Cloudflare 设置。';
    return 'Cloudflare 检测暂时失败，请重新检测。';
  }
  function gcmsCloudflareHeadline(check: GcmsAccessCheck): string {
    const cf = gcmsActionCloudflare(check);
    if (check.matched) return check.caddy?.can_auto_configure ? '域名已连接，准备配置 HTTPS' : '服务器环境需要确认';
    if (canCreateGcmsCloudflareA(check)) return check.redirect ? '还差一步：连接两个域名' : '还差一步：连接域名';
    if (canCutoverGcmsCloudflare(check)) return check.redirect ? '旧域名已识别，可以一起迁移' : '旧域名已识别，可以安全迁移';
    if (gcmsManualUnmatchedRoute(check)) return '有一个域名需要手动连接';
    if (!cf) return '需要先完成 DNS 连接';
    if (cf.status === 'connection_selection_required') return '选择管理这个域名的连接';
    if (['permission_error', 'ssl_unreadable'].includes(cf.status)) return '更新当前 Cloudflare 连接';
    if (['connection_required', 'zone_not_found'].includes(cf.status)) return '需要连接 Cloudflare 账号';
    return '需要你确认一项设置';
  }
  function gcmsCloudflareBadgeLabel(check: GcmsAccessCheck): string {
    const cf = gcmsActionCloudflare(check);
    if (check.matched) return '已连接';
    if (canCreateGcmsCloudflareA(check)) return '可以自动处理';
    if (canCutoverGcmsCloudflare(check)) return '可安全迁移';
    if (gcmsManualUnmatchedRoute(check)) return '需要设置';
    if (!cf) return '需要设置';
    if (cf.status === 'connection_selection_required') return '请选择连接';
    if (['record_missing', 'origin_mismatch', 'unsupported_record', 'zone_inactive', 'ssl_incompatible'].includes(cf.status)) return '需要确认';
    return cloudflareStatusLabel(cf);
  }
  function gcmsCloudflareActionLabel(check: GcmsAccessCheck): string {
    const cf = gcmsActionCloudflare(check);
    if ((check.matched && check.caddy?.can_auto_configure) || canCreateGcmsCloudflareA(check)) return '一键完成配置';
    if (canCutoverGcmsCloudflare(check)) return '安全迁移老域名';
    if (gcmsManualUnmatchedRoute(check)) return '查看处理建议';
    if (!cf) return '查看处理建议';
    if (cf.status === 'matched' || cf.status === 'record_missing') return '查看处理建议';
    if (cf.status === 'connection_selection_required') return '请选择 Cloudflare 连接';
    if (cf.status === 'connection_required') return '连接 Cloudflare';
    if (cf.status === 'zone_not_found') return '连接其他 Cloudflare 账号';
    if (cf.status === 'permission_error' || cf.status === 'ssl_unreadable') return '更新此连接的 Token';
    if (cf.status === 'api_error') return '重新检测';
    return '打开 Cloudflare 控制台';
  }
  async function copyGcmsValue(value: string) {
    try { await navigator.clipboard.writeText(value); say('已复制'); }
    catch { say('复制失败，请手动选择复制', 'err'); }
  }
  async function checkGcmsAccess() {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    const connId = gcmsAccess.connId;
    const intent = gcmsAccess.intent;
    const domain = gcmsAccess.domain.trim();
    const redirectDomain = gcmsAccess.redirectDomain.trim() || null;
    patchGcmsAccess({ checking: true, result: null, error: '', notice: '', phase: '正在识别 DNS 托管商并核验源站…', log: '' });
    try {
      const childSiteId = gcmsAccess.childSiteId;
      const migrationInstanceId = gcmsAccess.migrationInstanceId;
      const check = childSiteId != null && migrationInstanceId
        ? await invoke<GcmsAccessCheck>('gcms_remote_migration_site_access_check', { migrationInstanceId, siteId: childSiteId, domain, redirectDomain })
        : await invoke<GcmsAccessCheck>('gcms_remote_access_check', { connId, domain, redirectDomain, instancePath: gcmsAccess?.instancePath ?? null, instancePort: gcmsAccess?.instancePort ?? null });
      if (gcmsAccess?.connId === connId) patchGcmsAccess({
        checking: false,
        activeStep: intent === 'https_proxy' && check.matched && !!check.caddy ? 3 : 2,
        detailsOpen: false,
        check,
        domain: check.domain,
        redirectDomain: check.redirect?.domain ?? '',
        error: '',
        phase: '',
      });
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ checking: false, activeStep: gcmsAccess.check ? 2 : 1, error: String(e), phase: '' });
    }
  }
  async function selectGcmsCloudflareCandidate(check: GcmsCloudflareCheck, connectionId: string) {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    const candidate = (check.candidates ?? []).find((item) => item.connection_id === connectionId);
    if (!candidate) return;
    const zone = candidate.zone_name || check.zone_name;
    if (!candidate.permission_complete || candidate.status === 'permission_error') {
      openCfUpdateForGcms(connectionId, zone);
      return;
    }
    const connId = gcmsAccess.connId;
    patchGcmsAccess({ checking: true, error: '', notice: '', phase: `正在确认「${cloudflareCandidateLabel(candidate)}」可以管理 ${zone}…` });
    try {
      await invoke<Connection>('gcms_cloudflare_select_connection', { zone, connectionId });
      await refreshConns();
      if (gcmsAccess?.connId !== connId) return;
      patchGcmsAccess({ checking: false, phase: '', notice: `已固定使用「${cloudflareCandidateLabel(candidate)}」管理 ${zone}。` });
      await checkGcmsAccess();
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ checking: false, error: String(e), phase: '' });
    }
  }
  async function changeGcmsCloudflareConnection() {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    const cloudflare = gcmsProxyCloudflare(gcmsAccess.check);
    const zone = cloudflare?.zone_name;
    if (!zone) return;
    const connId = gcmsAccess.connId;
    patchGcmsAccess({ checking: true, result: null, error: '', notice: '', phase: `正在重新查找可管理 ${zone} 的连接…` });
    try {
      await invoke('gcms_cloudflare_clear_connection', { zone });
      await refreshConns();
      if (gcmsAccess?.connId !== connId) return;
      patchGcmsAccess({ checking: false, activeStep: 2, result: null, phase: '' });
      await checkGcmsAccess();
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ checking: false, error: String(e), phase: '' });
    }
  }

  function requestGcmsAccessPassword(
    options: { title: string; message: string; kind?: GcmsPasswordKind; confirmText?: string },
    run: (password: string) => Promise<void>,
  ) {
    if (!gcmsAccess) return;
    const access = gcmsAccess;
    const primaryStatus = !access.instancePath ? gcmsServer(access.connId).status : null;
    const primaryConn = conns.find((item) => item.id === access.connId);
    if (primaryStatus?.password_status === 'default' && primaryConn) {
      openGcmsPasswordEditor(primaryConn, primaryStatus);
      say('请先修改 GCMS 默认密码，再执行公网配置', 'err');
      return;
    }
    const migration = access.migrationInstanceId
      ? gcmsMigrationInstances.find((item) => item.id === access.migrationInstanceId)
      : null;
    requestVerifiedGcmsPassword({
      ...options,
      account: primaryStatus?.admin_user || 'admin',
      instance: migration?.source_name || primaryConn?.name || access.domain,
    }, {
      connId: access.connId,
      instancePath: access.instancePath,
      migrationInstanceId: access.migrationInstanceId,
    }, run);
  }

  async function createGcmsCloudflareA(adminPassword: string): Promise<GcmsAccessCheck | null> {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring || !gcmsAccess.check || !canCreateGcmsCloudflareA(gcmsAccess.check)) return null;
    const connId = gcmsAccess.connId;
    const domain = gcmsAccess.check.domain;
    const redirectDomain = gcmsAccess.check.redirect?.domain ?? null;
    patchGcmsAccess({ creatingDns: true, result: null, error: '', notice: '', phase: redirectDomain ? '正在 Cloudflare 安全连接两个域名…' : '正在 Cloudflare 创建仅 DNS 的 A 记录…' });
    try {
      const childSiteId = gcmsAccess.childSiteId;
      const migrationInstanceId = gcmsAccess.migrationInstanceId;
      const result = childSiteId != null && migrationInstanceId
        ? await invoke<GcmsCloudflareCreateResult>('gcms_remote_migration_site_create_a_record', { migrationInstanceId, siteId: childSiteId, domain, redirectDomain, adminPassword })
        : await invoke<GcmsCloudflareCreateResult>('gcms_cloudflare_create_a_record', {
            connId, domain, redirectDomain, adminPassword,
            instancePath: gcmsAccess.instancePath ?? null,
            instancePort: gcmsAccess.instancePort ?? null,
            migrationInstanceId: gcmsAccess.migrationInstanceId ?? null,
          });
      if (gcmsAccess?.connId !== connId) return null;
      const notice = result.created
        ? result.check.matched ? `已连接 ${result.created_domains.join('、')}，并完成源站核验。` : 'DNS 记录已创建，等待生效后请重新检测。'
        : result.check.matched ? '同值 A 记录已经存在，已重新完成核验。' : '同值 A 记录已经存在，请按下方提示完成后续核验。';
      patchGcmsAccess({ creatingDns: false, activeStep: 2, check: result.check, domain: result.check.domain, redirectDomain: result.check.redirect?.domain ?? '', error: '', notice, phase: '' });
      say(result.created ? 'Cloudflare DNS 记录已创建' : 'Cloudflare DNS 记录已经存在');
      return result.check;
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ creatingDns: false, error: String(e), phase: '' });
      throw e;
    }
  }
  async function configureGcmsAccess(checkOverride?: GcmsAccessCheck, adminPassword?: string) {
    const accessCheck = checkOverride ?? gcmsAccess?.check;
    if (!gcmsAccess || gcmsAccess.creatingDns || gcmsAccess.configuring || !accessCheck?.matched || !accessCheck.caddy?.can_auto_configure) return;
    if (!adminPassword) {
      requestGcmsAccessPassword({
        title: '配置公网访问',
        message: `将为 ${accessCheck.domain} 写入 Web 服务配置、申请 HTTPS，并按当前设置管理 Cloudflare 代理。`,
        confirmText: '验证并配置',
      }, async (password) => { await configureGcmsAccess(accessCheck, password); });
      return;
    }
    const connId = gcmsAccess.connId;
    const domain = accessCheck.domain;
    const redirectDomain = accessCheck.redirect?.domain ?? null;
    patchGcmsAccess({ configuring: true, activeStep: 3, result: null, error: '', phase: '准备配置…', log: '' });
    const onEvent = new Channel<GcmsInstallEvent>();
    onEvent.onmessage = (event) => {
      if (gcmsAccess?.connId !== connId) return;
      if (event.type === 'phase') patchGcmsAccess({ phase: event.message });
      else if (event.type === 'log') {
        const current = gcmsAccess.log;
        patchGcmsAccess({ log: [current, event.text].filter(Boolean).join('\n') });
      }
    };
    try {
      const childSiteId = gcmsAccess.childSiteId;
      const migrationInstanceId = gcmsAccess.migrationInstanceId;
      const result = childSiteId != null && migrationInstanceId
        ? await invoke<GcmsAccessApplyResult>('gcms_remote_migration_site_access_configure', { migrationInstanceId, siteId: childSiteId, domain, redirectDomain, enableCloudflareProxy: true, adminPassword, onEvent })
        : await invoke<GcmsAccessApplyResult>('gcms_remote_access_configure', { connId, domain, redirectDomain, enableCloudflareProxy: true, instancePath: gcmsAccess.instancePath ?? null, instancePort: gcmsAccess.instancePort ?? null, migrationInstanceId: gcmsAccess.migrationInstanceId ?? null, adminPassword, onEvent });
      if (gcmsAccess?.connId !== connId) return;
      if (!gcmsAccess.instancePath) patchGcmsServer(connId, { status: result.status, accessHealth: gcmsAccessHealthFromResult(result), error: '', phase: '' });
      patchGcmsAccess({ configuring: false, activeStep: 4, result, error: '', phase: result.https_ok ? '公网访问已就绪' : '配置已保存，等待 HTTPS 生效' });
      if (gcmsAccess.childSiteId != null && gcmsAccess.migrationInstanceId) void loadGcmsMigrationSites(gcmsAccess.migrationInstanceId);
      else if (gcmsAccess.migrationInstanceId) void loadGcmsMigrationInstances();
      say(result.https_ok
        ? result.cloudflare_proxy_applicable && !result.cloudflare_proxied ? '网站已可访问，Cloudflare 橙云需要确认' : gcmsAccess.childSiteId != null ? '子站域名已接管' : 'GCMS 公网访问已配置'
        : '配置已保存，HTTPS 可能仍在签发证书',
        result.https_ok && result.cloudflare_proxy_applicable && !result.cloudflare_proxied ? 'err' : 'ok');
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ configuring: false, error: String(e), phase: '' });
      throw e;
    }
  }
  async function cutoverGcmsCloudflare(check: GcmsAccessCheck, adminPassword?: string) {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring || !canCutoverGcmsCloudflare(check) || !gcmsAccess.migrationInstanceId) return;
    const routes = gcmsAccessRoutes(check).filter((route) => !route.matched);
    const oldRecords = routes.flatMap((route) => (route.cloudflare?.records ?? [])
      .filter((record) => record.record_type === 'A' || record.record_type === 'AAAA')
      .map((record) => `${route.domain} ${record.record_type} ${record.content}`));
    const childSite = gcmsAccess.childSiteId != null;
    if (!adminPassword) {
      requestGcmsAccessPassword({
        title: childSite ? '安全迁移子站域名' : '安全迁移老域名',
        message: `将 ${routes.map((route) => route.domain).join('、')} 切换到当前实例。\n当前记录：${oldRecords.join('；') || '未读取'}\n目标 IPv4：${check.server_ipv4[0]}\nPilot 会建立回滚点，失败时恢复旧记录。`,
        confirmText: '验证并迁移',
      }, async (password) => { await cutoverGcmsCloudflare(check, password); });
      return;
    }
    if (!gcmsAccess) return;
    const connId = gcmsAccess.connId;
    const domain = check.domain;
    const redirectDomain = check.redirect?.domain ?? null;
    patchGcmsAccess({ configuring: true, result: null, error: '', notice: '', phase: '正在建立 DNS 回滚点…', log: '' });
    const onEvent = new Channel<GcmsInstallEvent>();
    onEvent.onmessage = (event) => {
      if (gcmsAccess?.connId !== connId) return;
      if (event.type === 'phase') patchGcmsAccess({ phase: event.message });
      else if (event.type === 'log') patchGcmsAccess({ log: [gcmsAccess.log, event.text].filter(Boolean).join('\n') });
    };
    try {
      const result = await invoke<GcmsAccessApplyResult>('gcms_remote_access_cutover', {
        connId, domain, redirectDomain,
        instancePath: gcmsAccess.instancePath ?? null,
        instancePort: gcmsAccess.instancePort ?? null,
        migrationInstanceId: gcmsAccess.migrationInstanceId,
        childSiteId: gcmsAccess.childSiteId ?? null,
        adminPassword,
        onEvent,
      });
      if (gcmsAccess?.connId !== connId) return;
      patchGcmsAccess({ configuring: false, activeStep: 4, result, error: '', notice: '', phase: childSite ? '子站域名已迁移到新服务器' : '老域名已迁移到新服务器' });
      if (childSite && gcmsAccess.migrationInstanceId) void loadGcmsMigrationSites(gcmsAccess.migrationInstanceId);
      else void loadGcmsMigrationInstances();
      say(childSite ? '子站域名已安全迁移到新服务器' : '老域名已安全迁移到新服务器');
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ configuring: false, activeStep: 2, error: String(e), phase: '' });
      throw e;
    }
  }
  async function verifyGcmsAccess() {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    const connId = gcmsAccess.connId;
    const domain = gcmsAccess.domain;
    const redirectDomain = gcmsAccess.redirectDomain.trim() || null;
    patchGcmsAccess({ checking: true, error: '', phase: '正在重新检测 HTTPS 与页面资源…' });
    try {
      const result = await invoke<GcmsAccessApplyResult>('gcms_remote_access_verify', { connId, domain, redirectDomain, enableCloudflareProxy: true, instancePath: gcmsAccess.instancePath ?? null, instancePort: gcmsAccess.instancePort ?? null, migrationInstanceId: gcmsAccess.migrationInstanceId ?? null, childSiteId: gcmsAccess.childSiteId ?? null });
      if (gcmsAccess?.connId !== connId) return;
      if (!gcmsAccess.instancePath) patchGcmsServer(connId, { status: result.status, accessHealth: gcmsAccessHealthFromResult(result), error: '', phase: '' });
      patchGcmsAccess({ checking: false, activeStep: 4, result, error: '', phase: result.https_ok ? 'HTTPS 已就绪' : '等待 HTTPS 生效' });
      if (gcmsAccess.childSiteId != null && gcmsAccess.migrationInstanceId) void loadGcmsMigrationSites(gcmsAccess.migrationInstanceId);
      else if (gcmsAccess.migrationInstanceId) void loadGcmsMigrationInstances();
      say(result.https_ok
        ? result.cloudflare_proxy_applicable
          ? result.cloudflare_proxied ? 'HTTPS、页面资源与 Cloudflare 橙云已验证' : 'HTTPS 已验证，但 Cloudflare 橙云仍需确认'
          : 'HTTPS 与页面资源已验证'
        : 'HTTPS 暂未生效，请稍后再检测',
        result.https_ok && result.cloudflare_proxy_applicable && !result.cloudflare_proxied ? 'err' : 'ok');
    } catch (e) {
      if (gcmsAccess?.connId === connId) patchGcmsAccess({ checking: false, error: String(e), phase: '' });
    }
  }
  async function runGcmsCloudflareAction(check: GcmsAccessCheck) {
    if (!gcmsAccess || gcmsAccess.checking || gcmsAccess.creatingDns || gcmsAccess.configuring) return;
    const cf = gcmsActionCloudflare(check);
    if (check.matched) {
      if (check.caddy?.can_auto_configure) await configureGcmsAccess(check);
      else setGcmsAccessStep(3);
      return;
    }
    if (canCreateGcmsCloudflareA(check)) {
      requestGcmsAccessPassword({
        title: '连接域名并配置公网访问',
        message: `将为 ${check.domain} 创建缺失的 Cloudflare A 记录；解析生效后继续配置 HTTPS 与代理。`,
        confirmText: '验证并继续',
      }, async (adminPassword) => {
        const next = await createGcmsCloudflareA(adminPassword);
        if (!next?.matched || !next.caddy) return;
        if (next.caddy.can_auto_configure) await configureGcmsAccess(next, adminPassword);
        else patchGcmsAccess({ activeStep: 3, error: '' });
      });
      return;
    }
    if (canCutoverGcmsCloudflare(check)) {
      await cutoverGcmsCloudflare(check);
      return;
    }
    if (gcmsManualUnmatchedRoute(check)) {
      patchGcmsAccess({ detailsOpen: true });
      return;
    }
    if (!cf) {
      patchGcmsAccess({ detailsOpen: true });
      return;
    }
    if (cf.status === 'record_missing') {
      patchGcmsAccess({ detailsOpen: true });
      return;
    }
    if (cf.status === 'connection_selection_required') return;
    if (['permission_error', 'ssl_unreadable'].includes(cf.status) && cf.connection_id) {
      openCfUpdateForGcms(cf.connection_id, cf.zone_name);
      return;
    }
    if (['connection_required', 'zone_not_found', 'permission_error', 'ssl_unreadable'].includes(cf.status)) {
      openCfForGcms();
      return;
    }
    if (cf.status === 'api_error') {
      await checkGcmsAccess();
      return;
    }
    await openUrl(CF_DASH_URL);
  }
  function patchGcmsServer(id: string, patch: Partial<GcmsServerView>) {
    gcmsServers = { ...gcmsServers, [id]: { ...gcmsServer(id), ...patch } };
  }
  async function refreshGcmsServerAccessHealth(id: string, status: GcmsRemoteStatus) {
    if (gcmsAccessHealthChecking[id]) return;
    const domain = domainFromUrl(status.base_url);
    if (!domain) return;
    gcmsAccessHealthChecking = { ...gcmsAccessHealthChecking, [id]: true };
    try {
      const check = await invoke<GcmsAccessCheck>('gcms_remote_access_check', {
        connId: id,
        domain,
        redirectDomain: status.redirect_domain.trim() || null,
        instancePath: null,
        instancePort: null,
      });
      const cloudflareRoutes = gcmsAccessRoutes(check).map((route) => route.cloudflare).filter((value): value is GcmsCloudflareCheck => !!value);
      const previous = gcmsServer(id).accessHealth;
      patchGcmsServer(id, {
        accessHealth: {
          domain,
          checked: previous?.checked ?? false,
          https_ok: previous?.https_ok ?? false,
          verification_error: previous?.verification_error ?? '',
          cloudflare_checked: true,
          cloudflare_proxy_applicable: cloudflareRoutes.length > 0,
          cloudflare_proxied: cloudflareRoutes.length > 0 && cloudflareRoutes.every((route) => route.proxied),
          cloudflare_proxy_error: cloudflareRoutes.filter((route) => route.status !== 'matched').map((route) => route.detail).filter(Boolean).join('；'),
        },
      });
    } catch {
      // 菜单状态核验失败时保持灰色未知态；完整错误仍会在用户进入配置流程后展示。
    } finally {
      const next = { ...gcmsAccessHealthChecking };
      delete next[id];
      gcmsAccessHealthChecking = next;
    }
  }
  async function probeRemoteGcms(id: string, checkForUpdates = true) {
    if (gcmsInstalling[id]) return;
    patchGcmsServer(id, { checking: true, status: null, error: '', phase: '正在连接并检测…' });
    try {
      const status = await invoke<GcmsRemoteStatus>('gcms_remote_status', { connId: id });
      const previousHealth = gcmsServer(id).accessHealth;
      const accessHealth = previousHealth?.domain && previousHealth.domain === domainFromUrl(status.base_url) ? previousHealth : null;
      patchGcmsServer(id, { checking: false, status, accessHealth, error: '', phase: '' });
      if (checkForUpdates && status.installed && status.update_supported) void checkRemoteGcmsUpdate(id, true, true);
      if (gcmsPasswordEditor?.connId === id && !gcmsPasswordEditor.saving && status.password_status !== 'default') {
        closeGcmsPasswordEditor();
      }
    } catch (e) {
      patchGcmsServer(id, { checking: false, status: null, error: String(e), phase: '' });
    }
  }
  async function restartRemoteGcms(c: Connection, current: GcmsRemoteStatus) {
    if (gcmsServiceActions[c.id] || gcmsInstalling[c.id]) return;
    gcmsCardMenu = null;
    if (current.password_status === 'default') {
      openGcmsPasswordEditor(c, current);
      say('请先修改 GCMS 默认密码，再执行服务操作', 'err');
      return;
    }
    const action = current.running ? '重启' : '启动';
    requestVerifiedGcmsPassword({
      title: `${action} GCMS 服务`,
      message: current.running
        ? `端口 :${current.port || 8080} 会短暂不可访问；安装目录、数据与域名配置不会改变。`
        : `将按端口 :${current.port || 8080} 和现有配置启动，不会修改站点数据。`,
      account: current.admin_user || 'admin',
      instance: c.name,
    }, { connId: c.id }, async (adminPassword) => {
      gcmsServiceActions = { ...gcmsServiceActions, [c.id]: 'restart' };
      patchGcmsServer(c.id, { status: current, error: '', phase: current.running ? '正在重启 GCMS 服务…' : '正在启动 GCMS 服务…' });
      try {
        const status = await invoke<GcmsRemoteStatus>('gcms_remote_restart', { connId: c.id, adminPassword });
        patchGcmsServer(c.id, { status, error: '', phase: '' });
        say(`GCMS 服务已${action}`);
      } catch (e) {
        patchGcmsServer(c.id, { status: current, error: String(e), phase: '' });
        throw e;
      } finally {
        const next = { ...gcmsServiceActions };
        delete next[c.id];
        gcmsServiceActions = next;
      }
    });
  }
  async function stopRemoteGcms(c: Connection, current: GcmsRemoteStatus) {
    if (gcmsServiceActions[c.id] || gcmsInstalling[c.id] || !current.running) return;
    gcmsCardMenu = null;
    if (current.password_status === 'default') {
      openGcmsPasswordEditor(c, current);
      say('请先修改 GCMS 默认密码，再执行服务操作', 'err');
      return;
    }
    requestVerifiedGcmsPassword({
      title: '关闭 GCMS 服务',
      message: '网站与后台将不可访问；安装目录、数据、域名与配置都会保留，之后可以重新启动。',
      account: current.admin_user || 'admin',
      instance: c.name,
    }, { connId: c.id }, async (adminPassword) => {
      gcmsServiceActions = { ...gcmsServiceActions, [c.id]: 'stop' };
      patchGcmsServer(c.id, { status: current, error: '', phase: '正在关闭 GCMS 服务…' });
      try {
        const status = await invoke<GcmsRemoteStatus>('gcms_remote_stop', { connId: c.id, adminPassword });
        patchGcmsServer(c.id, { status, error: '', phase: '' });
        say('GCMS 服务已关闭');
      } catch (e) {
        patchGcmsServer(c.id, { status: current, error: String(e), phase: '' });
        throw e;
      } finally {
        const next = { ...gcmsServiceActions };
        delete next[c.id];
        gcmsServiceActions = next;
      }
    });
  }
  async function recheckRemoteGcms(c: Connection, current: GcmsRemoteStatus) {
    if (gcmsInstalling[c.id] || gcmsServer(c.id).checking) return;
    gcmsCardMenu = null;
    const domain = domainFromUrl(current.base_url);
    if (!domain) {
      await probeRemoteGcms(c.id);
      return;
    }
    patchGcmsServer(c.id, {
      checking: true,
      status: current,
      error: '',
      phase: '正在只读检查后台页面、样式资源与公网状态…',
    });
    try {
      const result = await invoke<GcmsAccessApplyResult>('gcms_remote_access_verify', {
        connId: c.id,
        domain,
        redirectDomain: current.redirect_domain.trim() || null,
        enableCloudflareProxy: false,
      });
      const error = result.https_ok
        ? ''
        : `页面检查未通过：${result.verification_error || 'HTTPS 或页面资源尚未就绪'}`;
      const previousHealth = gcmsServer(c.id).accessHealth;
      const checkedHealth = gcmsAccessHealthFromResult(result, false);
      const accessHealth = previousHealth?.domain === checkedHealth.domain
        ? {
            ...checkedHealth,
            cloudflare_checked: previousHealth.cloudflare_checked,
            cloudflare_proxy_applicable: previousHealth.cloudflare_proxy_applicable,
            cloudflare_proxied: previousHealth.cloudflare_proxied,
            cloudflare_proxy_error: previousHealth.cloudflare_proxy_error,
          }
        : checkedHealth;
      patchGcmsServer(c.id, { checking: false, status: result.status, accessHealth, error, phase: '' });
      say(
        result.https_ok ? '重新检测完成，后台页面与样式资源均正常' : '检测完成，但页面样式仍未恢复',
        result.https_ok ? 'ok' : 'err',
      );
    } catch (e) {
      const message = `重新检测失败：${String(e)}`;
      patchGcmsServer(c.id, { checking: false, status: current, error: message, phase: '' });
      say(message, 'err');
    }
  }
  async function refreshGcmsServers() {
    await Promise.all([
      ...sshServers.map((c) => probeRemoteGcms(c.id)),
      loadGcmsMigrationInstances(),
    ]);
  }
  function openGcmsInstaller() {
    switcherOpen = false;
    setupAddOpen = false;
    setupOpen = false;
    gcmsInstallOpen = true;
    void refreshGcmsServers();
  }
  async function installRemoteGcms(c: Connection) {
    if (gcmsInstalling[c.id]) return;
    gcmsInstalling = { ...gcmsInstalling, [c.id]: Date.now() };
    patchGcmsServer(c.id, { checking: false, status: null, accessHealth: null, error: '', phase: '准备安装…', log: '' });
    const onEvent = new Channel<GcmsInstallEvent>();
    onEvent.onmessage = (event) => {
      if (event.type === 'phase') patchGcmsServer(c.id, { phase: event.message });
      else if (event.type === 'log') {
        const current = gcmsServer(c.id).log;
        patchGcmsServer(c.id, { log: [current, event.text].filter(Boolean).join('\n') });
      }
    };
    try {
      const status = await invoke<GcmsRemoteStatus>('gcms_remote_install', { connId: c.id, onEvent });
      patchGcmsServer(c.id, { status, error: '', phase: '安装完成' });
      say(`「${c.name}」已安装 GCMS${status.version ? ` ${status.version}` : ''}`);
      if (status.password_status === 'default' && status.password_change_supported) {
        openGcmsPasswordEditor(c, status, true);
      }
    } catch (e) {
      patchGcmsServer(c.id, { status: null, error: String(e), phase: '安装失败' });
    } finally {
      const next = { ...gcmsInstalling }; delete next[c.id]; gcmsInstalling = next;
    }
  }
  $effect(() => {
    if (!Object.keys(gcmsInstalling).length && !Object.keys(gcmsUpgrading).length) return;
    gcmsInstallClock = Date.now();
    const timer = setInterval(() => (gcmsInstallClock = Date.now()), 500);
    return () => clearInterval(timer);
  });
  // 连接切换器里每条连接的右键菜单（新窗口打开 / 编辑 / 删除）。
  let connCtx = $state<null | { x: number; y: number; conn: Connection }>(null);
  // 删除确认期间保留连接切换器与右键菜单，让用户始终看得见操作来源；
  // 取消后仍回到原菜单，确认后才由 removeConn 主动收起右键菜单。
  let connCtxConfirmPinned = $state(false);
  function openConnCtx(e: MouseEvent, c: Connection) {
    e.preventDefault();
    e.stopPropagation(); // 别让全局那个输入框右键菜单也跳出来
    connCtx = { x: Math.min(e.clientX, window.innerWidth - 180), y: Math.min(e.clientY, window.innerHeight - 150), conn: c };
  }
  let connRemarkEdit = $state<null | { id: string; name: string; original: string; value: string; busy: boolean; error: string }>(null);
  function openConnRemark(c: Connection) {
    connCtx = null;
    switcherOpen = false;
    const value = c.remark?.trim() ?? '';
    connRemarkEdit = { id: c.id, name: c.name, original: value, value, busy: false, error: '' };
  }
  async function saveConnRemark() {
    if (!connRemarkEdit || connRemarkEdit.busy) return;
    connRemarkEdit.busy = true;
    connRemarkEdit.error = '';
    const value = connRemarkEdit.value.trim();
    try {
      const updated = await invoke<Connection>('set_connection_remark', { connId: connRemarkEdit.id, remark: value });
      conns = conns.map((c) => (c.id === updated.id ? updated : c));
      connRemarkEdit = null;
      say(value ? '连接备注已保存' : '连接备注已清除');
    } catch (e) {
      if (connRemarkEdit) {
        connRemarkEdit.error = String(e);
        connRemarkEdit.busy = false;
      }
    }
  }
  $effect(() => {
    if (!connCtx) return;
    const close = () => { if (!connCtxConfirmPinned) connCtx = null; };
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape' && !connCtxConfirmPinned) connCtx = null; };
    window.addEventListener('click', close);
    window.addEventListener('contextmenu', close);
    window.addEventListener('keydown', onKey);
    return () => {
      window.removeEventListener('click', close);
      window.removeEventListener('contextmenu', close);
      window.removeEventListener('keydown', onKey);
    };
  });
  async function openConnWindow(id: string) {
    try { await invoke('open_conn_window', { connId: id }); }
    catch (e) { say(String(e), 'err'); }
  }
  let footerEl = $state<HTMLElement | null>(null);
  $effect(() => {
    if (!setupAddOpen) return;
    const onDoc = (e: MouseEvent) => {
      if (setupAddEl && !setupAddEl.contains(e.target as Node)) setupAddOpen = false;
    };
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') setupAddOpen = false; };
    document.addEventListener('mousedown', onDoc, true);
    document.addEventListener('keydown', onKey);
    return () => {
      document.removeEventListener('mousedown', onDoc, true);
      document.removeEventListener('keydown', onKey);
    };
  });
  $effect(() => {
    if (!switcherOpen) return;
    const onDoc = (e: MouseEvent) => {
      const target = e.target as Element | null;
      if (connCtxConfirmPinned || target?.closest('[data-keep-connection-menu]')) return;
      if (footerEl && !footerEl.contains(e.target as Node)) switcherOpen = false;
    };
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape' && !connCtxConfirmPinned) switcherOpen = false; };
    // 捕获阶段：点空白（含拖拽区）也能关闭切换器。
    document.addEventListener('mousedown', onDoc, true);
    document.addEventListener('keydown', onKey);
    return () => { document.removeEventListener('mousedown', onDoc, true); document.removeEventListener('keydown', onKey); };
  });
  let flash = $state('');
  let flashKind = $state<'ok' | 'err'>('ok');

  type ConfirmKind = 'warning' | 'danger' | 'info';
  let confirmState = $state<null | { message: string; title: string; kind: ConfirmKind; confirmText: string; cancelText: string }>(null);
  let confirmResolve: ((value: boolean) => void) | null = null;

  function confirmDialog(message: string, options: { title?: string; kind?: ConfirmKind; confirmText?: string; cancelText?: string } = {}) {
    if (confirmResolve) confirmResolve(false);
    return new Promise<boolean>((resolve) => {
      confirmResolve = resolve;
      confirmState = {
        message,
        title: options.title || '请确认操作',
        kind: options.kind || 'warning',
        confirmText: options.confirmText || '确认',
        cancelText: options.cancelText || '取消',
      };
    });
  }

  function finishConfirm(value: boolean) {
    const resolve = confirmResolve;
    confirmResolve = null;
    confirmState = null;
    resolve?.(value);
  }

  type GcmsPasswordKind = 'warning' | 'danger';
  type GcmsPasswordRequest = {
    id: number;
    title: string;
    message: string;
    account: string;
    instance: string;
    kind: GcmsPasswordKind;
    confirmText: string;
    busy: boolean;
    error: string;
    verify: (password: string) => Promise<void>;
    onVerified?: (password: string) => Promise<void>;
  };
  type GcmsPasswordTarget = {
    connId: string;
    instancePath?: string;
    migrationInstanceId?: string;
  };
  type GcmsNativeUnlockOperation = 'public_access.apply' | 'public_access.clear_unverified' | 'themes.apply_live';
  type GcmsNativeUnlockResult = {
    operations: string[];
    expires_at: string;
    ttl_seconds: number;
  };
  let gcmsPasswordState = $state<GcmsPasswordRequest | null>(null);
  let gcmsPasswordRequestId = 0;
  let gcmsNativeUnlockGrants = $state<Record<string, number>>({});

  function gcmsNativeUnlockKey(connId: string, siteId: number, operation: GcmsNativeUnlockOperation): string {
    return `${connId}:${siteId}:${operation}`;
  }

  function hasGcmsNativeUnlock(connId: string, siteId: number, operation: GcmsNativeUnlockOperation): boolean {
    return (gcmsNativeUnlockGrants[gcmsNativeUnlockKey(connId, siteId, operation)] ?? 0) > Date.now() + 2_000;
  }

  function rememberGcmsNativeUnlock(
    connId: string,
    siteId: number,
    operation: GcmsNativeUnlockOperation,
    result: GcmsNativeUnlockResult,
  ) {
    // Tauri 每个 GCMS 连接只保留一枚短时令牌；新授权会覆盖同连接的旧授权，
    // 因此前端也只记住这次 operation，避免误以为其它操作仍然可用。
    const next = Object.fromEntries(
      Object.entries(gcmsNativeUnlockGrants).filter(([key]) => !key.startsWith(`${connId}:`)),
    );
    const ttlMs = Math.max(0, (result.ttl_seconds || 300) * 1_000 - 3_000);
    next[gcmsNativeUnlockKey(connId, siteId, operation)] = Date.now() + ttlMs;
    gcmsNativeUnlockGrants = next;
  }

  function forgetGcmsNativeUnlock(connId: string, siteId: number, operation: GcmsNativeUnlockOperation) {
    const key = gcmsNativeUnlockKey(connId, siteId, operation);
    if (!(key in gcmsNativeUnlockGrants)) return;
    const next = { ...gcmsNativeUnlockGrants };
    delete next[key];
    gcmsNativeUnlockGrants = next;
  }

  function isGcmsNativeUnlockError(error: unknown): boolean {
    return /unlock_required|(?:授权|解锁).*(?:失效|过期)|需要.*(?:重新授权|解锁)|重新验证.*后台密码|请先.*短时解锁/i.test(String(error));
  }

  async function unlockGcmsNativeOperation(
    connId: string,
    siteId: number,
    operation: GcmsNativeUnlockOperation,
    password: string,
  ) {
    try {
      const result = await invoke<GcmsNativeUnlockResult>('gcms_control_unlock', {
        connId,
        password,
        operations: [operation],
      });
      rememberGcmsNativeUnlock(connId, siteId, operation, result);
    } catch (error) {
      const message = String(error);
      if (/unknown_operation|未知的高风险操作|unlock_not_required|不需要密码解锁/i.test(message)) {
        if (operation === 'themes.apply_live') {
          throw new Error('当前 GCMS 版本尚未支持线上主题的密码验证，请先升级 GCMS 后再应用主题。');
        }
        if (operation === 'public_access.clear_unverified') {
          throw new Error('当前 GCMS 版本尚未支持安全清除未生效域名，请先升级 GCMS 后重试。');
        }
      }
      throw error;
    }
  }

  function requestGcmsPassword(
    options: { title: string; message: string; account?: string; instance?: string; kind?: GcmsPasswordKind; confirmText?: string },
    verify: (password: string) => Promise<void>,
    onVerified?: (password: string) => Promise<void>,
  ) {
    if (confirmResolve) finishConfirm(false);
    // 密码弹窗有自己的反馈区域；清掉旧 Toast，避免它被遮罩模糊后变成看不清的黑框。
    flash = '';
    gcmsPasswordRequestId += 1;
    gcmsPasswordState = {
      id: gcmsPasswordRequestId,
      title: options.title,
      message: options.message,
      account: options.account || 'admin',
      instance: options.instance || '',
      kind: options.kind || 'warning',
      confirmText: options.confirmText || '确认操作',
      busy: false,
      error: '',
      verify,
      onVerified,
    };
  }

  function requestVerifiedGcmsPassword(
    options: { title: string; message: string; account?: string; instance?: string; kind?: GcmsPasswordKind; confirmText?: string },
    target: GcmsPasswordTarget,
    onVerified: (password: string) => Promise<void>,
  ) {
    // 弹窗只承担身份校验；具体操作会在弹窗关闭后继续，因此按钮不再暗示两者同步完成。
    requestGcmsPassword({ ...options, confirmText: '验证密码' }, async (password) => {
      await invoke('gcms_remote_verify_admin_password', {
        connId: target.connId,
        instancePath: target.instancePath ?? null,
        migrationInstanceId: target.migrationInstanceId ?? null,
        adminPassword: password,
      });
    }, onVerified);
  }

  async function submitGcmsPassword(password: string) {
    const request = gcmsPasswordState;
    if (!request || request.busy) return;
    gcmsPasswordState = { ...request, busy: true, error: '' };
    try {
      await request.verify(password);
      if (gcmsPasswordState?.id === request.id) gcmsPasswordState = null;
      if (request.onVerified) {
        // 身份验证结束即卸载密码弹窗；后续长任务回到原抽屉展示状态与错误。
        await tick();
        void request.onVerified(password).catch((error) => {
          console.warn('GCMS 身份验证后的操作失败', error);
        });
      }
    } catch (error) {
      if (gcmsPasswordState?.id === request.id) {
        gcmsPasswordState = { ...request, busy: false, error: String(error) };
      }
    }
  }

  function cancelGcmsPassword() {
    if (!gcmsPasswordState?.busy) gcmsPasswordState = null;
  }

