    // Shell 就无法做命令与路径补全。终端聚焦时显式走用户输入通道；Shift+Tab
    // 保留终端通用的反向制表序列。带 Ctrl/Alt/Meta 的组合键仍交给 xterm/宿主。
    if (e.key === 'Tab' && !e.ctrlKey && !e.altKey && !e.metaKey) {
      e.preventDefault(); e.stopPropagation();
      t.input(e.shiftKey ? '\x1b[Z' : '\t', true);
      return false;
    }

