    // 这里直接走 xterm 的用户输入通道，macOS 也统一经过同一路径，且不会发送两次。
    if (e.key === 'Escape') {
      e.preventDefault(); e.stopPropagation();
      t.input('\x1b', true);
      return false;
    }
