    // 必须 open() 之后再挂，且要能回退 —— WebView 里 WebGL 不一定可用，
    // 上下文丢失（切显卡/系统回收）也要退回 DOM，否则整个终端会变黑。
    try {
      const { WebglAddon } = await import('@xterm/addon-webgl');
