      if (ev.type === 'data' && ev.b64) t.write(b64ToBytes(ev.b64));
      else if (ev.type === 'closed') {
        termOn = false;
        t.write(`\r\n\x1b[90m—— 连接已关闭${ev.error ? '：' + ev.error : ''}，按回车重新连接 ——\x1b[0m\r\n`);
      }
    };
    t.onData((d) => {
