      // 连接中（termBusy）也别触发，免得连点回车叠一队重连。
      if (!termOn) {
        if (d.includes('\r') && !termBusy) void reconnectTerm();
        return;
      }
      void invoke('ssh_input', { connId: id, b64: strToB64(d) });
    });
    t.onResize(({ cols, rows }) => { void invoke('ssh_resize', { connId: id, cols, rows }); });
