  // 键盘也能调（手柄是个 button，Tab 得到）
  function onColKey(e: KeyboardEvent, k: ColKey) {
    const d = e.key === 'ArrowLeft' ? 8 : e.key === 'ArrowRight' ? -8 : 0;
    if (!d) return;
    e.preventDefault();
    setColW(k, colW[k] + d);
    saveColW();
  }
