  const sftpRows = $derived.by(() => {
    const out: SftpRow[] = [];
    const walk = (dir: string, depth: number) => {
      for (const e of sortRows(sftpKids[dir] ?? [])) {
        const p = sftpJoin(dir, e.name);
        out.push({ ...e, path: p, depth });
        if (e.dir && !e.link && sftpOpenDirs.has(p)) walk(p, depth + 1);
