  .deployment-provider-card > div { min-width: 0; }
  .deployment-provider-card b, .deployment-provider-card small { display: block; }
  .deployment-provider-card b { font-size: 12.5px; }
  .deployment-provider-card small { margin-top: 2px; color: var(--dim); font-size: 10px; line-height: 1.45; }
  .deployment-provider-card em {
    flex: none;
    padding: 2px 7px;
    border-radius: 999px;
    background: #fff;
    color: var(--ok);
    font-size: 9.5px;
    font-style: normal;
    white-space: nowrap;
  }
  .deployment-option-list { padding: 0 11px; border: 1px solid var(--border); border-radius: 10px; background: #faf9f6; }
  .deployment-dns-actions { display: flex; align-items: center; gap: 7px; flex-wrap: wrap; }
  .deployment-manual-note {
    display: grid;
    gap: 2px;
    padding: 10px 11px;
    border: 1px dashed var(--border2);
    border-radius: 9px;
    color: var(--dim);
    font-size: 10.5px;
  }
  .deployment-manual-note b { color: var(--text); font-size: 11.5px; }
  .deployment-current-state {
    display: flex;
    align-items: center;
    gap: 9px;
    padding: 10px 11px;
    border-radius: 9px;
    background: #eff7f1;
  }
  .deployment-current-state > span {
    width: 24px;
    height: 24px;
    display: grid;
    place-items: center;
    border-radius: 50%;
    background: #dcefe2;
    color: var(--ok);
    font-weight: 700;
  }
  .deployment-current-state b, .deployment-current-state small { display: block; }
  .deployment-current-state b { font-size: 11.5px; }
  .deployment-current-state small { margin-top: 1px; color: var(--dim); font-size: 9.5px; }
  .deployment-review {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 8px;
    margin: 0;
    padding: 11px;
    border: 1px solid var(--border);
    border-radius: 10px;
    background: #faf9f6;
  }
  .deployment-review > div { min-width: 0; padding: 7px 8px; border-radius: 8px; background: #fff; }
  .deployment-review dt { color: var(--faint); font-size: 9.5px; }
  .deployment-review dd {
    margin: 2px 0 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    color: var(--text);
    font-size: 11px;
    font-weight: 600;
  }
  .deployment-safety-note {
    display: flex;
    align-items: flex-start;
    gap: 9px;
    padding: 10px 11px;
    border-radius: 10px;
    background: #f1f4f8;
  }
  .deployment-safety-note > span {
    width: 23px;
    height: 23px;
    flex: none;
    display: grid;
    place-items: center;
    border: 1px solid #b9c3ce;
    border-radius: 50%;
    color: #687788;
    font: 700 11px serif;
  }
  .deployment-safety-note b, .deployment-safety-note small { display: block; }
  .deployment-safety-note b { font-size: 11.5px; }
  .deployment-safety-note small { margin-top: 2px; color: var(--dim); font-size: 10px; line-height: 1.5; }
  .deployment-result-panel { gap: 11px; }
  .deployment-result {
    display: grid;
    grid-template-columns: 38px minmax(0, 1fr);
    align-items: center;
    gap: 11px;
    padding: 14px;
    border: 1px solid #d4e8da;
    border-radius: 12px;
    background: #f0f8f2;
  }
  .deployment-result.pending { border-color: #ead7b5; background: #fbf5e9; }
  .deployment-result.attention { border-color: #ecc8c1; background: #fcf2ef; }
  .deployment-result > span {
    width: 38px;
    height: 38px;
    display: grid;
    place-items: center;
    border-radius: 50%;
    background: #dbefe1;
    color: var(--ok);
    font-size: 18px;
    font-weight: 700;
  }
  .deployment-result.pending > span { background: #f4e6cb; color: #a16b1f; }
  .deployment-result.attention > span { background: #f6ddd8; color: #b54636; }
  .deployment-result b, .deployment-result small { display: block; }
  .deployment-result b { font-size: 13px; }
  .deployment-result small { margin-top: 3px; color: var(--dim); font-size: 10.5px; line-height: 1.5; }
  .deployment-result-url {
    display: grid;
    gap: 3px;
    padding: 10px 12px;
    border: 1px solid var(--border);
    border-radius: 10px;
    background: #fff;
  }
  .deployment-result-url span { color: var(--faint); font-size: 9.5px; }
  .deployment-result-link {
    min-width: 0;
    width: fit-content;
    max-width: 100%;
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 0;
    border: 0;
    background: transparent;
    color: var(--text);
    cursor: pointer;
  }
  .deployment-result-link b { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 14px; }
  .deployment-result-link svg { flex: none; }
  .deployment-result-link:hover { color: var(--accent); }
  .deployment-result-link:focus-visible { outline: 2px solid var(--accent); outline-offset: 3px; border-radius: 3px; }
  .deployment-result-url small { color: #a16b1f; font-size: 9.5px; }
  .deployment-result-url small.ok { color: var(--ok); }
  .deployment-result-status {
    min-width: 0;
    display: flex;
    align-items: center;
    gap: 3px;
  }
  .deployment-result-refresh {
    width: 16px;
    height: 16px;
    flex: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    border: 0;
    border-radius: 6px;
    background: transparent;
    color: var(--faint);
    cursor: pointer;
  }
  .deployment-result-refresh .rfz { width: 12px; height: 12px; }
  .deployment-result-refresh:hover { background: var(--rail); color: var(--text); }
  .deployment-result-refresh:focus-visible { outline: 2px solid var(--accent); outline-offset: 1px; }
  .deployment-result-refresh:disabled { opacity: .45; cursor: default; }
  .deployment-result-details { border-top: 1px solid var(--border); color: var(--dim); font-size: 10px; }
  .deployment-result-details summary { width: fit-content; padding-top: 9px; cursor: pointer; color: var(--dim); }
  .deployment-result-details > div { display: grid; gap: 7px; padding-top: 8px; }
  .deployment-result-details p { margin: 0; line-height: 1.55; }
  .deployment-messages { margin: 0; padding: 8px 11px 8px 27px; border-radius: 9px; background: #f7f6f2; color: var(--dim); font-size: 10px; line-height: 1.6; }
  .deployment-error { margin-top: 10px; }
  .deployment-footer {
    flex: none;
    min-height: 58px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    padding: 10px 18px;
    border-top: 1px solid var(--border);
    background: #fff;
  }
  .deployment-footer > div { display: flex; align-items: center; gap: 6px; flex-wrap: wrap; }
  .deployment-change-domain {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 4px 1px;
    border: 0;
    border-radius: 5px;
    background: transparent;
    color: var(--dim);
    font: 500 10px/1.3 inherit;
    cursor: pointer;
  }
  .deployment-change-domain:hover { color: var(--text); }
  .deployment-change-domain:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }
  .deployment-change-domain:disabled { opacity: .45; cursor: default; }
  @media (max-width: 620px) {
    .sites-global-grid, .sites-grid { grid-template-columns: 1fr; }
    .integration-range-row, .integration-form-grid { grid-template-columns: 1fr; }
    .integration-form-grid .full { grid-column: auto; }
    .cloudflare-auth-form { grid-template-columns: 1fr; }
    .cloudflare-auth-form > button { grid-column: auto; }
    .modal.deployment-modal { width: 100vw !important; height: 100vh; max-height: 100vh; border-radius: 0; }
    .deployment-body { flex: 1; }
    .deployment-wizard { height: 100%; max-height: none; }
    .deployment-steps { padding-inline: 12px; }
    .deployment-step b { font-size: 9.5px; }
    .deployment-stage { flex: 1; padding: 14px; }
    .deployment-provider-card { grid-template-columns: 32px minmax(0, 1fr); }
    .deployment-provider-card em { grid-column: 2; justify-self: start; }
    .deployment-review { grid-template-columns: 1fr; }
    .deployment-footer { padding-inline: 14px; }
  }

  /* 排期视图 */
  .sched-inner { max-width: 720px; margin: 0 auto; padding: 18px 24px 24px; }
  /* 密度条 + 站点筛选钉在滚动区顶部 */
  .sched-sticky { position: sticky; top: 0; z-index: 5; background: var(--bg); margin: -18px -4px 8px; padding: 14px 4px 2px; }
  /* 排期密度条：未来 6 周每天一格，深浅=条数 */
  /* 列数跟着格子数走（auto-fit），别再写死 42 —— 加了「过去一周」之后写死的列数会把格子挤扁。
     从 SCHED_PAST_DAYS 推的话又得让 JS 和 CSS 两头对同一个数，迟早对不上。 */
  .sched-density { display: grid; grid-template-columns: repeat(auto-fit, minmax(0, 1fr)); grid-auto-flow: column; gap: 3px; margin: 2px 0 12px; } /* 缝别加宽：总宽固定，缝变宽就是从格子身上扣（试过 4px，全部格子肉眼可见变小） */
  .sd-cell { position: relative; aspect-ratio: 1; border: none; border-radius: 3px; background: #ecebe6; padding: 0; cursor: default; }
  /* 「今天」左侧的分界线：过去｜今天/未来 的界碑，画在 3px 缝正中（两侧各 1px 空隙）、
     比格子矮一圈（上下各缩 1px）——不占格（等宽网格塞真元素会多出一列），扫一眼定位今天。 */
  .sd-cell.today::before { content: ''; position: absolute; left: -2px; top: 1px; bottom: 1px; width: 1px; background: rgba(160, 60, 43, .65); }
  .sd-cell.l1 { background: #e4c7b4; cursor: pointer; }
  .sd-cell.l2 { background: #d19a76; cursor: pointer; }
  .sd-cell.l3 { background: #b96a44; cursor: pointer; }
  .sd-cell.l4 { background: #a03c2b; cursor: pointer; }
  /* 过去的日子调淡：它们是「已经发生的」，不该和未来的排期抢注意力 */
  .sd-cell.past { opacity: .55; }
  .sd-cell.today { box-shadow: inset 0 0 0 1px #c98d70; background: #f3e7dd; }
  .sd-cell.today.l1, .sd-cell.today.l2, .sd-cell.today.l3, .sd-cell.today.l4 { box-shadow: inset 0 0 0 1px rgba(255,255,255,.55); }
  .sched-grp { scroll-margin-top: 96px; } /* 跳转落点让开顶部钉住的密度条 */
  .sched-grp-n { margin-left: 8px; font-weight: 400; color: var(--faint); font-size: 11px; }
  /* 排期站点筛选：安静的文字胶囊，选中才着色 */
  .sched-filter { display: flex; flex-wrap: wrap; gap: 2px; margin: 4px 0 6px; }
  .sf-chip { display: inline-flex; align-items: center; gap: 5px; border: none; background: none; padding: 3px 9px; border-radius: 999px; font: inherit; font-size: 12px; color: var(--dim, #6b675f); cursor: pointer; }
  .sf-chip:hover { background: #f1efe9; color: var(--text, #26241f); }
  /* 选中态：不上底色，一圈淡边（inset ring 不引起布局跳动） */
  .sf-chip.on { background: none; box-shadow: inset 0 0 0 1px #e6cabb; color: var(--accent); }
  .sf-chip.sf-all { background: none; padding-left: 0; }
  .sf-chip.sf-all.on { background: none; box-shadow: none; color: var(--accent); font-weight: 600; }
  .sched-body small { display: inline-flex; align-items: center; gap: 4px; }
  .sched-t { color: var(--accent); font-weight: 500; }
  .sched-done { margin-left: 6px; color: var(--ok); font-size: 10px; border: 1px solid currentColor; border-radius: 3px; padding: 0 3px; line-height: 13px; }
  /* 非文章条目的型标（链接/页面/商品…）：中性灰，和绿色「已发布」拉开语义层级 */
  .sched-kind { margin-left: 6px; color: var(--faint); font-size: 10px; border: 1px solid currentColor; border-radius: 3px; padding: 0 3px; line-height: 13px; }
  .sched-filter-dd { display: inline-block; margin: 4px 0 6px; }
  .sched-grp { padding: 16px 2px 6px; }
  .sched-grp:first-child { padding-top: 4px; }
  .sched-item { display: flex; align-items: center; gap: 14px; padding: 11px 14px; background: var(--card);
    border: 1px solid var(--border); border-radius: 11px; margin-bottom: 8px; box-shadow: var(--shadow-sm); }
  .sched-time { flex: none; width: 128px; font-size: 12.5px; color: var(--accent); font-weight: 550;
    font-variant-numeric: tabular-nums; }
  .sched-body { flex: 1; min-width: 0; }
  .sched-body b { display: block; font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .sched-body small { color: var(--dim); font-size: 11.5px; }
  .sched-open { flex: none; border: none; background: none; padding: 0; font-size: 12px; color: var(--accent); cursor: pointer; }
  .sched-err { max-width: 720px; margin: 18px auto; }
  .center-hint { text-align: center; color: var(--dim); padding: 40px 0; }
  .sched-empty { text-align: center; color: var(--dim); padding: 12vh 24px; }
  .sched-empty .cal-mark { font-size: 34px; }
  .sched-empty .cal-mark svg { display: block; margin: 0 auto; }
  .sched-empty b { display: block; margin: 12px 0 6px; color: var(--text); font-size: 16px; }
  .sched-empty p { margin: 0 auto; max-width: 380px; font-size: 13px; }

  /* AI 提议的定时任务卡 */
  .proposal { margin-top: 10px; border: 1px solid #ddd9ce; background: #f7f6f2; border-radius: 12px; padding: 12px 14px; display: flex; flex-direction: column; gap: 5px; align-items: flex-start; }
  .proposal-head { font-size: 12px; color: var(--accent); font-weight: 600; }
  .proposal-title { font-size: 14px; }
  .proposal-meta { font-size: 12px; color: var(--dim); }
  .proposal-prompt { font-size: 12.5px; color: var(--text); background: #fff; border: 1px solid var(--border); border-radius: 8px; padding: 7px 9px; width: 100%; white-space: pre-wrap; word-break: break-word; }
  .proposal .btn { margin-top: 3px; }
  .proposal-done { margin-top: 3px; display: inline-flex; align-items: center; gap: 5px; font-size: 12.5px; font-weight: 500; color: #16a34a; }

  /* 定时任务 */
  .task-card { display: flex; align-items: flex-start; gap: 12px; padding: 13px 14px; background: var(--card);
    border: 1px solid var(--border); border-radius: 12px; margin-bottom: 8px; box-shadow: var(--shadow-sm); }
  .task-card.off { opacity: .62; }
  .task-toggle { padding-top: 1px; }
  .switch { width: 34px; height: 20px; border-radius: 12px; border: none; background: #d3d0c8; cursor: pointer; padding: 0; position: relative; transition: background .15s; }
  .switch.on { background: var(--accent); }
  .switch span { position: absolute; top: 2px; left: 2px; width: 16px; height: 16px; border-radius: 50%; background: #fff; transition: transform .15s; box-shadow: var(--shadow-sm); }
  .switch.on span { transform: translateX(14px); }
  .task-body { flex: 1; min-width: 0; }
  .task-body b { font-weight: 550; }
  .task-meta { display: flex; align-items: center; flex-wrap: wrap; gap: 4px; font-size: 12px; color: var(--dim); margin-top: 3px; }
  .task-meta .cdot { color: var(--faint); }
  .task-last { font-size: 12px; margin-top: 5px; color: var(--dim); display: flex; gap: 6px; flex-wrap: wrap; align-items: baseline; }
  .task-last.ok { color: var(--ok); } .task-last.error { color: var(--err); }
  .task-actions { display: flex; align-items: center; gap: 4px; flex: none; }

  .modal.wide { width: min(520px, 94vw); }
  .trow { display: flex; gap: 12px; }
  .tfield { display: flex; flex-direction: column; gap: 5px; flex: 1; min-width: 0; }
  .tfield > span { font-size: 12px; color: var(--dim); }
  /* 任务运行记录 */
  .trun { border: 1px solid var(--border); border-radius: 10px; padding: 9px 11px; }
  .trun-head { display: flex; align-items: center; gap: 8px; font-size: 12.5px; min-width: 0; }
  .trun-badge { flex: none; padding: 1px 7px; border-radius: 999px; font-size: 11px; }
  .trun-badge.ok { background: #e7f0e8; color: #3e7a4e; }
  .trun-badge.err { background: #f7e8e4; color: #a03c2b; }
  /* 订阅限额顺延（非失败语义）：琥珀 warn 色系 + 小时钟 */
  .trun-badge.defer { background: #fdf6e3; color: #9a6b00; display: inline-flex; align-items: center; gap: 3px; }
  .trun-site.is-defer { color: #9a6b00; }
  .defer-tag { margin-left: 6px; padding: 0 6px; border-radius: 999px; background: #fdf6e3; color: #9a6b00; font-size: 10.5px; vertical-align: 1px; }
  .trun-sum { color: var(--dim); font-size: 12px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; flex: 1; min-width: 0; }
  .trun-sites { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 7px; }
  .trun-site { display: inline-flex; align-items: center; gap: 5px; padding: 3px 9px; border: 1px solid var(--border2); border-radius: 999px; font-size: 12px; background: var(--card); color: inherit; font-family: inherit; cursor: pointer; }
  .trun-site:hover { border-color: var(--accent); color: var(--accent); }
  .trun-site.is-err { cursor: help; color: #a03c2b; border-color: #ecd4cc; background: #fbf3f0; }
  .trun-fallback { padding-left: 6px; border-left: 1px solid var(--border2); color: #7a6440; font-size: 10px; white-space: nowrap; }
  /* 多站点胶囊 */
  .tsites { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 2px; }
  .tsite-chip { display: inline-flex; align-items: center; gap: 5px; padding: 3px 6px 3px 8px; border: 1px solid var(--border2); border-radius: 999px; font-size: 12px; background: var(--card); }
  .tsite-chip button { border: none; background: none; padding: 0 2px; font-size: 13px; line-height: 1; color: var(--faint); cursor: pointer; }
  .tsite-chip button:hover { color: var(--accent); }
  .launcher-sites { margin-top: 7px; }
  .sitebuild-note { display: flex; align-items: center; justify-content: space-between; gap: 12px; margin-top: 8px; padding: 0 3px; color: var(--faint); font-size: 11.5px; }
  .sitebuild-note button { flex: none; border: 0; background: none; color: var(--accent); font: inherit; cursor: pointer; padding: 2px 3px; }
  .sitebuild-note button:hover { text-decoration: underline; }
  .sitebuild-note button:disabled { color: var(--faint); cursor: default; text-decoration: none; }
  .multi-add { flex: none; border: none; background: none; padding: 2px 4px; font-size: 11.5px; color: var(--faint); cursor: pointer; border-radius: 6px; }
  .multi-add:hover { color: var(--accent); background: #f1efe9; }
  /* 任务弹窗里的 模型+强度（对话同款 ModelFx），套输入框外观（--ctl-h 定高，内容 flex 垂直居中） */
  .tfield-fx { border: 1px solid var(--border2); border-radius: 8px; padding: 0 3px; background: var(--card); height: var(--ctl-h); box-sizing: border-box; display: flex; align-items: center; }
  .tfield-fx :global(.fx) { width: 100%; }
  .tfield-fx :global(.fx-trigger) { width: 100%; justify-content: flex-start; font-size: 13px; padding: 4px 8px; }
  .tfield-fx :global(.fx-chev) { margin-left: auto; }
  .tcheck { display: flex; align-items: center; gap: 8px; font-size: 13px; cursor: pointer; }
  .tcheck input { width: auto; }

  .composer-wrap { flex: none; padding: 10px 24px 20px; }
  .composer-wrap .composer { max-width: 760px; margin: 0 auto; }
  /* 新站上线准备：属于输入区而不是聊天消息。默认保持一条紧凑摘要，按需展开真实待办。 */
  .site-ready { max-width: 760px; margin: 0 auto 6px; border: 1px solid #ddd9cf; border-radius: 10px; background: rgba(255, 255, 255, .96); overflow: hidden; }
  .site-ready.blocked { border-color: #ead5b8; background: #fffdf9; }
  .site-ready.complete { border-color: #cfe3d5; background: #fbfefc; }
  .site-ready-summary { min-height: 40px; display: flex; align-items: stretch; gap: 4px; padding: 2px 4px 2px 5px; }
  .site-ready-toggle { flex: 1; min-width: 0; border: 0; border-radius: 7px; background: none; padding: 3px 5px; display: flex; align-items: center; gap: 6px; color: var(--text); text-align: left; cursor: pointer; }
  .site-ready-toggle:hover { background: #f6f4ef; }
  .site-ready-icon { width: 24px; height: 24px; flex: none; display: inline-flex; align-items: center; justify-content: center; border-radius: 7px; color: #756e62; background: #f1efe9; }
  .site-ready.blocked .site-ready-icon { color: #a46b16; background: #fbf1df; }
  .site-ready.complete .site-ready-icon { color: #287248; background: #e9f5ed; }
  .site-ready-copy { flex: 1; min-width: 0; display: flex; flex-direction: column; gap: 0; }
  .site-ready-title { min-width: 0; display: flex; align-items: baseline; gap: 6px; white-space: nowrap; }
  .site-ready-title strong { flex: none; font-size: 12.5px; font-weight: 650; }
  .site-ready-title small { min-width: 0; overflow: hidden; text-overflow: ellipsis; color: var(--dim); font-size: 11px; }
  .site-ready-detail { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--faint); font-size: 10.5px; line-height: 1.35; }
  .site-ready-chev { flex: none; color: var(--faint); transition: transform .15s; }
  .site-ready-chev.open { transform: rotate(180deg); }
  .site-ready-continue { align-self: center; flex: none; min-width: 62px; height: 26px; padding: 0 9px; border: 0; border-radius: 7px; background: var(--accent); color: #fff; display: inline-flex; align-items: center; justify-content: center; gap: 4px; font-size: 11px; font-weight: 550; cursor: pointer; }
  .site-ready-continue-icon { display: inline-block; vertical-align: -2px; }
  .site-ready-continue:hover { background: var(--accent-h); }
  .site-ready-continue.unlock { background: #a7651d; }
  .site-ready-continue.unlock:hover { background: #8e5317; }
  .site-ready-continue:disabled { opacity: .55; cursor: default; }
  .site-ready-refresh { align-self: center; flex: none; width: 26px; height: 26px; padding: 0; border: 0; border-radius: 7px; background: transparent; color: var(--faint); display: inline-flex; align-items: center; justify-content: center; cursor: pointer; }
  .site-ready-refresh :global(.rfz) { width: 12px; height: 12px; }
  .site-ready-refresh:hover { background: #f6f4ef; color: var(--text); }
  .site-ready-refresh:disabled { opacity: .5; cursor: default; }
  .site-ready-body { border-top: 1px solid #ebe8e0; padding: 5px; }
  .site-ready-list { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 5px; }
  .site-ready-item { min-width: 0; min-height: 41px; padding: 6px 7px; border: 1px solid #e9e6de; border-radius: 8px; background: #fbfaf7; display: flex; align-items: center; gap: 6px; color: var(--text); text-align: left; cursor: pointer; }
  .site-ready-item:hover { border-color: #d6d1c5; background: #f7f5f0; }
  .site-ready-item:disabled { opacity: .72; cursor: default; }
  .site-ready-item:disabled:hover { border-color: #e9e6de; background: #fbfaf7; }
  .site-ready-dot { width: 7px; height: 7px; flex: none; border-radius: 50%; background: #a9a49a; }
  .site-ready-item.blocker .site-ready-dot { background: #b64a38; }
  .site-ready-item.todo .site-ready-dot { background: #c78b2b; }
  .site-ready-item-copy { flex: 1; min-width: 0; }
  .site-ready-item-copy b, .site-ready-item-copy small { display: block; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .site-ready-item-copy b { font-size: 11.5px; font-weight: 600; }
  .site-ready-item-copy small { margin-top: 1px; color: var(--faint); font-size: 10px; }
  .site-ready-item-act { flex: none; color: var(--dim); font-size: 10.5px; }
  .site-ready-item.blocker .site-ready-item-act { color: #a53a29; }
  .site-ready-all { min-height: 45px; display: flex; align-items: center; gap: 8px; padding: 5px 8px; color: #287248; }
  .site-ready-all > span { width: 24px; height: 24px; flex: none; display: inline-flex; align-items: center; justify-content: center; border-radius: 50%; background: #e9f5ed; font-size: 12px; }
  .site-ready-all b, .site-ready-all small { display: block; }
  .site-ready-all b { font-size: 11.5px; }
  .site-ready-all small { margin-top: 1px; color: var(--dim); font-size: 10px; }
  .site-ready-foot { min-height: 27px; margin-top: 5px; padding: 3px 3px 0 9px; border-top: 1px solid #efede7; display: flex; align-items: flex-end; justify-content: space-between; color: var(--faint); font-size: 10px; }
  .site-ready-foot button { border: 0; border-radius: 6px; background: none; padding: 3px 5px; display: inline-flex; align-items: center; gap: 4px; color: var(--dim); font-size: 10.5px; cursor: pointer; }
  .site-ready-foot button:hover:not(:disabled) { color: var(--text); background: #f2f0eb; }
  .site-ready-foot button:disabled { opacity: .5; cursor: default; }
  .site-ready-foot svg.spin { animation: rspin .7s linear infinite; }

  /* ---- 按钮 / 弹窗 ---- */
  /* 动作按钮统一尺度：13px 字 + 6px 14px 内边距，高约 30px（与输入框/下拉同高，主次同高）。 */
  .btn { background: #fff; color: var(--text); border: 1.5px solid var(--border2); border-radius: 8px; padding: 6px 14px; cursor: pointer; font-size: 13px; line-height: 1.25; }
  .btn:hover { background: #f6f5f1; } .btn:disabled { opacity: .5; cursor: default; }
  .btn.primary { background: var(--accent); border-color: var(--accent); color: #fff; } .btn.primary:hover { background: var(--accent-h); }
  .btn.ghost { border-color: var(--border); }
  .btn.small { padding: 4px 10px; font-size: 12px; }
  .btn.sm { padding: 5px 12px; font-size: 12px; border-radius: 8px; }
  .btn.soft { display: inline-flex; align-items: center; gap: 6px; padding: 3px 12px; background: #fff; color: var(--text); border: 1px solid var(--border2); border-radius: 9px; font-weight: 500; }
  .btn.soft:hover { background: var(--rail); border-color: #cfccc2; }
  .btn.soft .plus-ic { color: var(--dim); }
  /* 无边框动作按钮（头部次要动作）：去边框去底，仅 hover 有淡底 */
  .btn.bare { border: none; background: none; }
  .btn.bare:hover { background: var(--rail); border-color: transparent; }
  .authbtn { display: inline-flex; align-items: center; gap: 3px; background: none; border: none; padding: 1px 2px; color: var(--accent); font-size: 12px; font-weight: 550; line-height: 1; cursor: pointer; }
  .authbtn:hover { color: var(--accent-h); }
  .permit-card { border: 1px solid var(--border2); border-radius: 11px; overflow: hidden; background: #fff; max-width: 480px; }
  .permit-card.danger { border-color: #f0d9a8; }
  .permit-head { display: flex; align-items: center; gap: 7px; padding: 8px 12px; font-size: 12px; font-weight: 600; color: var(--text); background: #f6f5f1; border-bottom: 0.5px solid var(--border); }
  .permit-card.danger .permit-head { color: #8a5a08; background: #fdf6e6; border-bottom-color: #f0e3c4; }
  .permit-dot { width: 7px; height: 7px; border-radius: 50%; background: #b45309; flex: none; }
  .permit-tag { margin-left: auto; font-size: 10px; font-weight: 600; color: #b45309; background: #faf1d8; padding: 1px 7px; border-radius: 5px; }
  .permit-desc { padding: 10px 12px 0; font-size: 13px; font-weight: 550; color: var(--text); line-height: 1.55; word-break: break-word; }
  .permit-meta { padding: 3px 12px 0; font-size: 11px; color: var(--dim); }
  .permit-more { display: block; margin: 7px 12px 0; padding: 0; border: 0; background: none; font-size: 11px; color: var(--dim); cursor: pointer; text-align: left; }
  .permit-more:hover { color: var(--text); }
  .permit-cmd { display: block; margin: 6px 12px 0; font-size: 12px; background: #17130f; color: #e8dcc8; padding: 8px 10px; border-radius: 7px; white-space: pre-wrap; word-break: break-all; max-height: 180px; overflow-y: auto; }
  .permit-act { display: flex; gap: 8px; padding: 10px 12px 12px; }
  .permit-act .btn { flex: 1; }
  .cf-mark { flex: none; display: inline-block; vertical-align: middle; }
  .hero-btns { display: flex; gap: 10px; flex-wrap: wrap; justify-content: center; }
  .setup-add { position: relative; display: inline-flex; }
  .setup-add-trigger { width: 27px; height: 27px; padding: 0; }
  .setup-add-trigger.open { color: var(--text); background: #f1efe9; }
  .setup-add-menu {
    position: absolute; z-index: 8; top: calc(100% + 5px); right: 0; width: 216px; padding: 5px;
    background: var(--panel); border: 1px solid var(--border); border-radius: 10px;
    box-shadow: 0 10px 28px rgba(30, 25, 15, .15); animation: pop .1s ease-out;
  }
  .setup-add-menu button {
    width: 100%; min-height: 34px; padding: 7px 9px; border: 0; border-radius: 7px; background: none;
    display: flex; align-items: center; gap: 9px; color: var(--text); cursor: pointer; text-align: left;
    font: inherit; font-size: 12.5px; font-weight: 500; letter-spacing: 0; text-transform: none;
  }
  .setup-add-menu button:hover { background: #f4f3ef; }
  .setup-add-menu button:disabled { opacity: .5; cursor: default; }
  .setup-add-menu button :global(svg) { flex: none; color: var(--dim); }
  .mask.cf-mask { z-index: 70; }
  .modal.cf-modal { z-index: 80; width: min(440px, 94vw); max-height: 88vh; }
  .cf-step { border-top: 0.5px solid var(--border); padding-top: 12px; margin-top: 6px; }
  .cf-step:first-child { border-top: none; padding-top: 0; margin-top: 0; }
  .cf-step-t { font-size: 13px; color: var(--text); margin: 0 0 7px; line-height: 1.5; }
  .cf-update-target { display: flex; align-items: center; gap: 9px; margin-bottom: 9px; padding: 9px 10px; border: 1px solid #dfe7e2; border-radius: 9px; background: #f4f8f5; }
  .cf-update-target > span { width: 28px; height: 28px; border-radius: 8px; background: #fff; display: inline-flex; align-items: center; justify-content: center; flex: none; }
  .cf-update-target > div { min-width: 0; }
  .cf-update-target b, .cf-update-target small { display: block; }
  .cf-update-target b { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 13px; }
  .cf-update-target small { margin-top: 2px; color: var(--dim); font-size: 10.5px; overflow-wrap: anywhere; }
  .cf-update-verified { display: flex; align-items: center; gap: 8px; margin-top: 8px; padding: 8px 9px; border-radius: 9px; background: #fbf3e7; color: #8a5a08; }
  .cf-update-verified.ok { background: #edf7f0; color: #287248; }
  .cf-update-verified > span { width: 22px; height: 22px; border-radius: 50%; background: rgb(255 255 255 / .75); display: inline-flex; align-items: center; justify-content: center; flex: none; font-weight: 700; }
  .cf-update-verified b, .cf-update-verified small { display: block; }
  .cf-update-verified b { font-size: 11.5px; }
  .cf-update-verified small { margin-top: 1px; color: var(--dim); font-size: 10px; }
  .cf-perms { margin: 0 0 9px; padding-left: 0; list-style: none; display: flex; flex-direction: column; gap: 3px; }
  .cf-perms li { font-size: 12px; color: var(--dim); padding-left: 13px; position: relative; }
  .cf-perms li::before { content: '·'; position: absolute; left: 4px; color: #f6821f; font-weight: 700; }
  .cf-perms li b { color: var(--text); font-weight: 550; }
  .cf-row { display: flex; gap: 8px; }
  .cf-row .tin { flex: 1; }
  .wr-note { display: flex; align-items: center; gap: 7px; width: fit-content; max-width: 100%; margin-top: 12px; font-size: 12px; color: #8a5a08; }
  .wr-note .wr-ic { flex: none; color: #d9a400; }
  .wr-note span { color: #8a5a08; }
  .wr-btn { flex: none; border: none; background: #d9a400; color: #fff; font-size: 11px; font-weight: 500; padding: 3px 9px; border-radius: 6px; cursor: pointer; }
  .wr-btn:hover { background: #c08f00; }
  .wr-btn:disabled { opacity: .85; cursor: default; }
  .wr-spin { display: inline-block; width: 10px; height: 10px; border: 1.6px solid #fff; border-right-color: transparent; border-radius: 50%; animation: rspin .7s linear infinite; margin-right: 5px; vertical-align: -1px; }
  .cf-perms-toggle { display: inline-flex; align-items: center; gap: 5px; background: none; border: none; padding: 0 0 8px; font-size: 12px; color: var(--dim); cursor: pointer; }
  .cf-perms-toggle:hover { color: var(--text); }
  .cf-chev { flex: none; transition: transform .12s; }
  .cf-chev.open { transform: rotate(180deg); }
  /* 启动页底栏空间不足时先收项目名，避免它把后面的风格/权限控件挤到一起。 */
  .cf-proj-in {
    flex: 0 1 190px; width: 190px; min-width: 72px; max-width: 190px;
    border: none; background: none; font-size: 13px; color: var(--text); padding: 3px 6px; outline: none;
    white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
  }
  .cf-proj-in::placeholder { color: #b3ada2; }
  .cb-prev { position: relative; display: inline-flex; align-items: center; gap: 4px; white-space: nowrap; font-size: 12px; padding: 3px 8px; border: none; background: none; color: var(--accent); cursor: pointer; font-weight: 500; border-radius: 6px; }
  .cb-prev:hover:not(:disabled) { background: var(--rail); }
  .cb-prev:disabled { opacity: .45; cursor: default; }
  .cb-prev.dim { color: var(--dim); font-weight: 400; }
  .cb-prev svg { flex: none; }
  /* 自定义悬停提示（不用系统 title） */
  .cf-bar { max-width: 760px; margin: 0 auto 6px; display: flex; align-items: center; gap: 2px; flex-wrap: wrap; }
  /* 等待消息（排队）条：琥珀色调，区别于普通输入 */
  .queued-row { display: flex; align-items: center; gap: 8px; margin: 10px 12px 0; padding: 6px 8px 6px 11px; background: #fbf6ea; border: 1px solid #f0e2c0; border-radius: 9px; font-size: 12.5px; }
  .queued-ic { flex: none; color: #b45309; display: inline-flex; }
  .queued-t { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--dim); }
  .queued-btn { flex: none; border: none; background: none; color: var(--accent); font-size: 12px; cursor: pointer; padding: 2px 4px; }
  .queued-btn:hover { text-decoration: underline; }
  .queued-x { flex: none; border: none; background: none; color: var(--faint); font-size: 15px; line-height: 1; cursor: pointer; padding: 0 3px; }
  .queued-x:hover { color: var(--err); }
  .send.queue { background: var(--accent); color: #fff; }
  .attach-row { display: flex; flex-wrap: wrap; align-items: center; gap: 6px; padding: 10px 14px 2px; }
  .attach-chip { display: inline-flex; align-items: center; gap: 6px; max-width: 190px; padding: 3px 4px 3px 6px; background: var(--panel); border: 1px solid var(--border2); border-radius: 8px; font-size: 12px; }
  .attach-img { width: 24px; height: 24px; object-fit: cover; border-radius: 4px; flex: none; }
  .attach-ic { color: var(--dim); flex: none; display: inline-flex; }
  .attach-name { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--text); }
  .attach-x { flex: none; border: none; background: none; color: var(--dim); cursor: pointer; font-size: 14px; line-height: 1; padding: 0 2px; }
  /* 用户气泡里的附件卡（只读，白底衬在浅色气泡上） */
  .ub-atts { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 8px; }
  .ub-atts.only { margin-top: 0; }
  .ub-att { display: inline-flex; align-items: center; gap: 6px; max-width: 220px; padding: 4px 10px 4px 8px; background: #fff; border: 1px solid var(--border2); border-radius: 8px; font-size: 12px; }
  .ub-att-img { padding: 0; border: 1px solid var(--border2); border-radius: 10px; overflow: hidden; cursor: zoom-in; line-height: 0; background: repeating-conic-gradient(#ececea 0 25%, #fff 0 50%) 0 0 / 14px 14px; display: inline-flex; align-items: center; justify-content: center; min-width: 44px; min-height: 34px; }
  /* 按图片原始比例呈现（纯像素上限、不裁切），宽 logo/竖图都能看到全貌；点击仍可放大。
     注意不能用 max-width:min(…,100%)：容器 shrink-to-fit，百分比循环引用会让整条声明失效。 */
  .ub-att-img img { display: block; max-width: 260px; max-height: 180px; width: auto; height: auto; }
  .ub-att-img.ph { display: inline-block; width: 128px; height: 96px; cursor: default; animation: phpulse 1.2s ease-in-out infinite; }
  /* 助手消息里的生图产物：与用户附件同款卡片，气泡外基底微调 */
  .gen-imgs { margin-top: 6px; }
  .ub-att.as-btn { cursor: pointer; font: inherit; font-size: 12px; color: inherit; }
  .ub-att.as-btn:hover { border-color: var(--border3, var(--border2)); }
  @keyframes phpulse { 0%, 100% { opacity: .55; } 50% { opacity: .9; } }
  .ub-att-ic { flex: none; display: inline-flex; color: var(--dim); }
  .ub-att-n { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--text); }
  .attach-x:hover { color: var(--err); }
  .attach-loading { font-size: 11px; color: var(--dim); }
  /* 提示词库 */
  .prompt-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(272px, 1fr)); gap: 12px; }
  .prompt-card { display: flex; flex-direction: column; background: var(--card); border: 1px solid var(--border2); border-radius: 12px; padding: 13px 14px 11px; }
  .prompt-top { display: flex; align-items: center; gap: 7px; margin-bottom: 6px; }
  .prompt-title { font-size: 13.5px; font-weight: 600; color: var(--text); flex: 1; min-width: 0; }
  .prompt-tag { flex: none; font-size: 10px; font-weight: 600; color: var(--dim); background: #e7e4dd; padding: 1px 6px; border-radius: 5px; }
  .prompt-body { margin: 0 0 11px; font-size: 12.5px; line-height: 1.5; color: var(--dim); display: -webkit-box; -webkit-line-clamp: 5; line-clamp: 5; -webkit-box-orient: vertical; overflow: hidden; }
  .prompt-acts { display: flex; align-items: center; gap: 4px; margin-top: auto; }
  .prompt-act { position: relative; width: 28px; height: 28px; display: inline-flex; align-items: center; justify-content: center; border: none; border-radius: 8px; background: none; color: var(--dim); cursor: pointer; }
  .prompt-act:hover { color: var(--text); background: var(--rail); }
  .prompt-act svg { flex: none; }
  /* 模板库单独一个更宽的容器：grid 本来就是 auto-fill（会自己长列），真正卡住它的是
     .sched-inner 的 720px —— 三列要 3*272+2*12+48 = 876px，720 差得远，所以窗口再宽也只有两列。
     日程页还得用窄栏（那是读列表的），所以不改 .sched-inner，另起一个。 */
  .tmpl-inner { max-width: 1180px; margin: 0 auto; padding: 18px 24px 24px; }
  .th-line { display: flex; align-items: baseline; gap: 8px; min-width: 0; }
  /* 提示挪到标题**同一行**了。`.th-info small` 那 2px 上间距是给「标题下面那行」准备的，
     这里得清掉；选择器带上 .tmpl-hint 才压得过它（它带元素选择器，分更高）。 */
  .th-info small.tmpl-hint { margin-top: 0; color: var(--faint); font-size: 11.5px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  /* 负边距抵掉筹码自己的内边距 —— 那 8px/3px 是**点击热区**，不该算进视觉间距：
     - 左：不抵的话整排比上面的「模板库」缩进 8px，看着就是没对齐。
     - 下：不抵的话筹码文字离底边比标题离顶边多出 3px 的死空（上 6 / 下 10.5），上下就不一致。 */
  .tmpl-chips { display: flex; flex-wrap: wrap; gap: 2px; margin-top: 5px; margin-left: -8px; margin-bottom: -3px; }
  /* 无外框、无底：选中只靠**颜色加重**（--dim → --text）。
     ★ 故意不动 font-weight：字重一变宽度就变，点一下整排筹码会跟着挪位。 */
  .tmpl-chip { display: inline-flex; align-items: center; gap: 3px; padding: 3px 8px; border: 0; border-radius: 999px; background: transparent; color: var(--dim); font-size: 12px; cursor: pointer; }
  .tmpl-chip:hover { color: var(--text); }
  .tmpl-chip:focus-visible { outline: 2px solid var(--accent); outline-offset: 1px; }
  .tmpl-chip.on { color: var(--text); }
  .tc-ic { flex: none; margin-right: 1px; opacity: 0.7; }
  .tc-n { font-size: 10px; opacity: 0.55; font-variant-numeric: tabular-nums; }
  /* ★ 240 是**默认窗口能放下两列**倒推出来的，别再往上调：
     默认 820 宽、左栏 240 → 内容 580，减 48 内边距 = 532。两列 = 2*240+12 = 492 ✓。
     上一版写 272 要 556 > 532，就差这一点，默认窗口直接掉成**一列**。
     再宽才 3 列（≈1050）、4 列（≈1300，到 1180 封顶就不再加）。 */
  .tmpl-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 12px; }
  /* 从全局搜索跳过来时闪一下：一屏十几张卡，跳到了也认不出是哪张 */
  @keyframes tmplFlash { from { box-shadow: 0 0 0 2px var(--accent); } to { box-shadow: 0 0 0 2px transparent; } }
  .tmpl-card.tmpl-flash { animation: tmplFlash 1.4s ease-out; }
  .tmpl-card { display: flex; flex-direction: column; background: var(--card); border: 1px solid var(--border2); border-radius: 12px; overflow: hidden; }
  .tmpl-thumb { position: relative; height: 158px; overflow: hidden; background: #fff; display: flex; align-items: center; justify-content: center; border-bottom: 1px solid var(--border); }
  .tmpl-frame { position: absolute; top: 0; left: 0; width: 1280px; height: 860px; border: 0; transform: scale(0.23); transform-origin: top left; pointer-events: none; background: #fff; }
  .tmpl-letter { font-size: 40px; font-weight: 600; color: #a03c2b; }
  .tmpl-hover { position: absolute; inset: 0; display: flex; align-items: flex-end; justify-content: center; gap: 8px; padding: 10px; background: linear-gradient(to top, rgba(0, 0, 0, .4), rgba(0, 0, 0, .05) 45%, transparent 70%); opacity: 0; transition: opacity .12s; }
  .tmpl-card:hover .tmpl-hover { opacity: 1; }
  .tmpl-act { position: relative; width: 26px; height: 26px; display: inline-flex; align-items: center; justify-content: center; border: none; border-radius: 7px; background: rgba(255, 255, 255, .95); color: var(--text); cursor: pointer; box-shadow: 0 2px 8px rgba(0, 0, 0, .15); }
  .tmpl-act.primary { background: var(--accent); color: #fff; }
  .tmpl-act:hover { transform: translateY(-1px); }
  .tmpl-act svg { flex: none; width: 13px; height: 13px; }
  .tmpl-body { padding: 10px 12px 12px; flex: 1; }
  .tmpl-body b { font-size: 13px; }
  .tmpl-sub { display: flex; align-items: baseline; justify-content: space-between; gap: 8px; margin-top: 4px; }
  .tmpl-desc { flex: 1; min-width: 0; font-size: 12px; color: var(--dim); line-height: 1.4; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .tmpl-meta { flex: none; display: inline-flex; align-items: center; gap: 6px; font-size: 11px; color: #b3ada2; }
  .tmpl-pg { color: var(--dim); background: var(--border); border-radius: 4px; padding: 0 4px; line-height: 15px; }
  .site-grp-fav { width: 14px; height: 14px; border-radius: 3px; flex: none; object-fit: cover; }
  .plus-ic { flex: none; }
  .icon-btn { background: none; border: none; cursor: pointer; padding: 6px; border-radius: 8px; color: var(--dim); display: inline-flex; align-items: center; justify-content: center; }
  .icon-btn:hover { background: #f1efe9; color: var(--text); }
  .icon-btn:disabled { opacity: .55; cursor: default; }
  .rfz { display: block; }
  .rfz.spin { animation: rspin .8s linear infinite; }
  @keyframes rspin { to { transform: rotate(360deg); } }
  @keyframes pop { from { opacity: 0; transform: translateY(4px); } }
  .x { background: none; border: none; color: var(--faint); font-size: 20px; cursor: pointer; line-height: 1; }
  .x:hover { color: var(--err); } .x.sm { font-size: 15px; }

  .mask { position: fixed; inset: 0; background: rgba(25,20,10,.28); z-index: 50; }
  .sheet, .modal { position: fixed; z-index: 60; background: var(--bg); border: 1px solid var(--border); box-shadow: var(--shadow-lg); display: flex; flex-direction: column; }
  .sheet { top: 0; right: 0; bottom: 0; width: min(400px, 92vw); border-radius: 0; }
  /* margin:auto 居中而非 transform——transform 会给内部 position:fixed 的下拉菜单
     制造 containing block，菜单被钳进弹窗坐标系再被 overflow:hidden 裁掉（遮挡）。 */
  .modal { inset: 0; margin: auto; height: fit-content; max-height: 88vh; width: min(440px, 92vw); border-radius: 14px; overflow: hidden; }
  .sheet-head { box-sizing: border-box; min-height: 48px; display: flex; justify-content: space-between; align-items: center; padding: 7px 14px; border-bottom: 1px solid var(--border); }
  .sheet-head > b { min-width: 0; overflow: hidden; font-size: 13.5px; line-height: 1.2; text-overflow: ellipsis; white-space: nowrap; }
  .sheet-body { padding: 16px 18px; overflow-y: auto; display: flex; flex-direction: column; gap: 7px; }
  .new-site-mask { z-index: 72; }
  .modal.new-site-choice-modal, .modal.quick-site-modal { z-index: 73; border-radius: 18px; }
  .modal.new-site-choice-modal { width: min(460px, calc(100vw - 40px)); }
  /* 主窗口使用 Overlay 标题栏，窗口左上角约 30px 属于系统控制区。
     高表单至少留出 36px 上边距，避免弹窗和 macOS 红黄绿按钮争抢同一区域。 */
  .modal.quick-site-modal { width: min(620px, calc(100vw - 40px)); max-height: min(680px, calc(100vh - 72px)); }
  .new-site-head { min-height: 48px; padding: 7px 14px; }
  .new-site-head > div { min-width: 0; display: grid; gap: 1px; }
  .new-site-head > div > b { font-size: 14px; line-height: 1.2; }
  .new-site-head > div > small { color: var(--faint); font-size: 10px; line-height: 1.25; }
  .new-site-choice-body { gap: 8px; padding: 14px 16px 13px; }
  .new-site-choice-card {
    width: 100%; min-width: 0; display: grid; grid-template-columns: 40px minmax(0, 1fr); align-items: center; gap: 11px;
    padding: 12px; border: 1px solid var(--border2); border-radius: 12px; background: #fff; color: var(--text);
    text-align: left; cursor: pointer; transition: border-color .15s, background .15s, transform .15s, box-shadow .15s;
  }
  .new-site-choice-card:hover { border-color: #ccc6ba; background: #fdfcf9; transform: translateY(-1px); box-shadow: var(--shadow-sm); }
  .new-site-choice-card:focus-visible { outline: none; border-color: #b8a98d; box-shadow: 0 0 0 3px rgb(180 146 85 / 13%); }
  .new-site-choice-card.recommended { border-color: #ddc7a1; background: #fffdf8; }
  .new-site-choice-icon { width: 40px; height: 40px; display: grid; place-items: center; border-radius: 10px; color: var(--dim); background: #f1f0ec; }
  .new-site-choice-icon.ai { color: #a55232; background: #f9eee8; }
  .new-site-choice-copy { min-width: 0; display: grid; gap: 3px; }
  .new-site-choice-title { display: flex; align-items: center; gap: 6px; }
  .new-site-choice-title b { font-size: 13.5px; }
  .new-site-choice-title em { padding: 1px 7px; border-radius: 999px; background: #f4e8d2; color: #9a5b0b; font-size: 10px; font-style: normal; font-weight: 650; }
  .new-site-choice-copy > small { color: var(--dim); font-size: 11px; line-height: 1.45; }
  .new-site-choice-copy > span:last-child { color: var(--accent); font-size: 11px; font-weight: 600; }
  .new-site-choice-note { margin: 2px 2px 0; color: var(--faint); font-size: 10px; line-height: 1.45; text-align: center; }
  .quick-site-form { min-height: 0; display: flex; flex: 1 1 auto; flex-direction: column; overflow: hidden; }
  .quick-site-body { min-height: 0; gap: 10px; padding: 13px 17px; }
  .quick-site-target {
    display: grid; grid-template-columns: 34px minmax(0, 1fr) auto; align-items: center; gap: 9px;
    padding: 9px 10px; border: 1px solid var(--border); border-radius: 11px; background: #faf9f6;
  }
  .quick-site-target-mark { width: 34px; height: 34px; display: grid; place-items: center; border-radius: 9px; background: #fff; box-shadow: var(--shadow-sm); }
  .quick-site-target > span:nth-child(2) { min-width: 0; display: grid; grid-template-columns: auto minmax(0, 1fr); align-items: baseline; column-gap: 8px; }
  .quick-site-target small { grid-column: 1 / -1; color: var(--faint); font-size: 10px; }
  .quick-site-target b { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 13px; }
  .quick-site-target em { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--faint); font-size: 10.5px; font-style: normal; }
  .quick-site-target > i { display: inline-flex; align-items: center; gap: 4px; padding: 2px 8px; border-radius: 999px; background: #eceae4; color: var(--dim); font-size: 10px; font-style: normal; white-space: nowrap; }
  .quick-site-target > i.ready { background: #e4f4ea; color: var(--ok); }
  .quick-site-target > i.ready > span { font-weight: 700; }
  .quick-site-target > i.blocked { background: var(--err-soft); color: var(--err); }
  .quick-site-target > i.checking > span { width: 9px; height: 9px; box-sizing: border-box; border: 1.3px solid currentColor; border-top-color: transparent; border-radius: 50%; animation: upd-spin .7s linear infinite; }
  .quick-site-fields { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 10px; }
  .quick-site-fields .tfield { gap: 5px; }
  .quick-site-fields .tin { height: 36px; padding-inline: 11px; font-size: 12.5px; }
  .quick-site-fields .tfield > small { min-height: 14px; color: var(--faint); font-size: 9.5px; line-height: 1.4; }
  .quick-site-fields .tfield > small.invalid { color: var(--err); }
  .quick-site-label-row { display: flex; align-items: center; justify-content: space-between; gap: 8px; }
  .quick-site-label-row > button { padding: 0; border: 0; background: transparent; color: var(--dim); font: inherit; font-size: 10px; cursor: pointer; }
  .quick-site-label-row > button:hover:not(:disabled) { color: var(--text); text-decoration: underline; text-underline-offset: 2px; }
  .quick-site-label-row > button:disabled { color: var(--faint); cursor: default; }
  .quick-site-options { min-width: 0; margin: 0; padding: 0; border: 0; }
  .quick-site-options legend { margin-bottom: 5px; color: var(--dim); font-size: 11.5px; }
  .quick-site-kind-grid, .quick-site-seed-grid { display: grid; gap: 7px; }
  .quick-site-kind-grid { grid-template-columns: repeat(3, minmax(0, 1fr)); }
  .quick-site-seed-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
  .quick-site-kind-grid > label, .quick-site-seed-grid > label {
    min-width: 0; display: grid; grid-template-columns: 16px minmax(0, 1fr); align-items: start; gap: 7px; padding: 8px 9px;
    border: 1px solid var(--border2); border-radius: 10px; background: #fff; cursor: pointer;
  }
  .quick-site-kind-grid > label:hover, .quick-site-seed-grid > label:hover { background: #fcfbf8; }
  .quick-site-kind-grid > label.selected, .quick-site-seed-grid > label.selected { border-color: #b7a27e; background: #fbf7ef; box-shadow: inset 0 0 0 1px rgb(155 119 55 / 8%); }
  .quick-site-kind-grid input, .quick-site-seed-grid input { width: 14px; height: 14px; margin: 1px 0 0; accent-color: #a65737; }
  .quick-site-kind-grid label > span, .quick-site-seed-grid label > span { min-width: 0; display: grid; gap: 2px; }
  .quick-site-kind-grid b, .quick-site-seed-grid b { font-size: 12px; }
  .quick-site-kind-grid small, .quick-site-seed-grid small { color: var(--dim); font-size: 9.8px; line-height: 1.4; }
  .quick-site-warning { display: grid; gap: 2px; padding: 7px 9px; border: 1px solid #efd4a6; border-radius: 9px; background: #fff8eb; color: #86520e; }
  .quick-site-warning b { font-size: 11.5px; }
  .quick-site-warning span { font-size: 10.5px; line-height: 1.5; }
  .quick-site-error { display: flex; align-items: center; justify-content: space-between; gap: 12px; }
  .quick-site-error > span { min-width: 0; }
  .quick-site-error > button { flex: none; padding: 0; border: 0; background: transparent; color: var(--err); font: inherit; font-size: 11px; font-weight: 600; cursor: pointer; }
  .quick-site-footer { flex: none; display: flex; align-items: center; justify-content: space-between; gap: 8px; padding: 5px 17px 7px; border-top: 1px solid var(--border); background: #fff; }
  .quick-site-back { min-height: 27px; display: inline-flex; align-items: center; gap: 3px; padding: 3px 1px; border: 0; background: transparent; color: var(--dim); font: inherit; font-size: 11.5px; cursor: pointer; }
  .quick-site-back:hover:not(:disabled) { color: var(--text); }
  .quick-site-back:disabled { opacity: .5; cursor: default; }
  .quick-site-back svg { flex: none; }
  .quick-site-footer .btn.primary { min-height: 29px; padding: 4px 11px; border-radius: 7px; font-size: 11.5px; }
  .quick-site-review { gap: 10px; }
  .quick-site-review-hero { display: grid; grid-template-columns: 38px minmax(0, 1fr) auto; align-items: center; gap: 9px; }
  .quick-site-review-hero > span:first-child { width: 38px; height: 38px; display: grid; place-items: center; border-radius: 10px; background: #f1f0ec; color: var(--dim); }
  .quick-site-review-hero > div { min-width: 0; display: grid; gap: 1px; }
  .quick-site-review-hero b { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 16px; }
  .quick-site-review-hero small { color: var(--dim); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11px; }
  .quick-site-review-hero em { padding: 3px 9px; border-radius: 999px; background: #e6f4eb; color: var(--ok); font-size: 10px; font-style: normal; font-weight: 650; }
  .quick-site-review-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); margin: 0; overflow: hidden; border: 1px solid var(--border); border-radius: 12px; }
  .quick-site-review-grid > div { min-width: 0; display: flex; align-items: center; justify-content: space-between; gap: 10px; padding: 8px 10px; }
  .quick-site-review-grid > div:nth-child(odd) { border-right: 1px solid var(--border); }
  .quick-site-review-grid > div:nth-child(n + 3) { border-top: 1px solid var(--border); }
  .quick-site-review-grid dt { color: var(--faint); font-size: 10.5px; }
  .quick-site-review-grid dd { min-width: 0; margin: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--text); font-size: 11.5px; font-weight: 600; text-align: right; }
  .quick-site-impact { padding: 9px 10px; border: 1px solid var(--border); border-radius: 11px; background: #faf9f6; }
  .quick-site-impact > b { font-size: 12px; }
  .quick-site-impact ul { display: grid; gap: 3px; margin: 6px 0; padding-left: 18px; color: var(--dim); font-size: 10.5px; line-height: 1.45; }
  .quick-site-impact li::marker { color: var(--faint); }
  .quick-site-impact p { margin: 0; padding-top: 6px; border-top: 1px solid var(--border); color: var(--faint); font-size: 10px; line-height: 1.45; }
  .quick-site-success { align-items: center; gap: 7px; padding-block: 22px 19px; text-align: center; }
  .quick-site-success-mark { width: 50px; height: 50px; display: grid; place-items: center; border-radius: 50%; background: #e4f4ea; color: var(--ok); }
  .quick-site-success > div:nth-child(2) { display: grid; gap: 1px; margin-top: 2px; }
  .quick-site-success > div:nth-child(2) b { font-size: 18px; }
