  @keyframes gcms-progress { 0% { transform: translateX(-110%); } 100% { transform: translateX(340%); } }
  .gcms-facts { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; margin: 10px 0 0 39px; }
