  .gcms-instance-card { min-width: 0; display: grid; gap: 7px; padding: 9px; border: 1px solid #d7e6dc; border-radius: 9px; background: #fbfefc; }
  .gcms-instance-card.error { border-color: #ead2c8; background: #fffaf8; }
