  .gcms-auto-actions .gcms-advanced-toggle { flex: none; min-height: 32px; padding: 0 10px; border: 1px solid var(--border2); border-radius: 8px; background: #fff; color: var(--dim); font-size: 9.5px; white-space: nowrap; }
