  .transfer-entry { width: 100%; margin-top: 13px; padding: 9px 0; border: 0; border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); background: transparent; color: var(--text); display: flex; align-items: center; gap: 9px; text-align: left; cursor: pointer; }
  .transfer-entry:hover { color: var(--accent); }
  .transfer-entry-ic { width: 28px; height: 28px; display: inline-flex; align-items: center; justify-content: center; border-radius: 8px; background: #f2eee8; color: var(--dim); flex: none; }
  .transfer-entry > span:nth-child(2) { min-width: 0; display: grid; gap: 2px; }
  .transfer-entry b { font-size: 12px; font-weight: 650; }
  .transfer-entry small { color: var(--faint); font-size: 10px; font-weight: 400; }
  .transfer-entry-arrow { margin-left: auto; color: var(--faint); flex: none; }
  .transfer-sheet { width: min(480px, 94vw); }
  .transfer-sheet .sheet-head > div { min-width: 0; display: grid; gap: 2px; }
  .transfer-sheet .sheet-head small { color: var(--faint); font-size: 9.5px; line-height: 1.2; font-weight: 400; }
  .transfer-body { gap: 12px; }
  .transfer-tabs { display: grid; grid-template-columns: 1fr 1fr; gap: 3px; padding: 3px; border-radius: 9px; background: #f1efe9; }
  .transfer-tabs button { min-height: 34px; border: 0; border-radius: 7px; background: transparent; color: var(--dim); font: inherit; font-size: 12px; cursor: pointer; }
  .transfer-tabs button.active { background: #fff; color: var(--text); box-shadow: 0 1px 4px rgb(35 29 20 / 10%); font-weight: 650; }
  .transfer-intro { margin: 0; color: var(--dim); font-size: 11px; line-height: 1.55; }
  .transfer-section-title { margin-top: 2px; color: var(--faint); font-size: 10.5px; font-weight: 650; }
  .transfer-checks { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }
  .transfer-check, .transfer-sensitive { min-width: 0; display: flex; align-items: flex-start; gap: 8px; padding: 8px 9px; border: 1px solid var(--border); border-radius: 8px; background: #fbfaf7; cursor: pointer; }
  .transfer-check:hover, .transfer-sensitive:hover { border-color: #d8c2b8; background: #fff; }
  .transfer-check input, .transfer-sensitive input { margin: 2px 0 0; accent-color: var(--accent); flex: none; }
  .transfer-check span, .transfer-sensitive span { min-width: 0; display: grid; gap: 2px; }
  .transfer-check b, .transfer-sensitive b { font-size: 11px; font-weight: 600; }
  .transfer-check small, .transfer-sensitive small { color: var(--faint); font-size: 9.5px; line-height: 1.35; }
  .transfer-check-all { grid-column: 1 / -1; border-color: #dbc6bc; background: #fdf8f5; }
  .transfer-sensitive { border-color: #e6d3a8; background: #fffaf0; }
  .transfer-password { display: grid; gap: 5px; }
  .transfer-password-label { color: var(--dim); font-size: 10.5px; font-weight: 600; }
  .transfer-password-label em { color: var(--faint); font-style: normal; font-weight: 400; }
  .transfer-password .tin { width: 100%; box-sizing: border-box; }
  .transfer-warn, .transfer-error, .transfer-notice, .transfer-preview { margin: 0; padding: 8px 10px; border-radius: 8px; font-size: 10.5px; line-height: 1.5; }
  .transfer-warn { color: #8a6420; background: #fff8e8; border: 1px solid #ecd9a0; }
  .transfer-error { color: var(--err); background: #fdf0ed; border: 1px solid #e8c4bc; }
  .transfer-notice { color: #34704a; background: #edf8f0; border: 1px solid #c9e4d0; }
  .transfer-action { width: 100%; justify-content: center; }
  .transfer-import-row { display: flex; align-items: center; gap: 8px; }
  .transfer-import-row > span { min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; color: var(--dim); font-size: 10px; }
  .transfer-preview { display: grid; gap: 3px; color: var(--text); background: #f6f4ef; border: 1px solid var(--border); }
  .transfer-preview small { color: var(--dim); font-size: 10px; }
  .transfer-modes { display: grid; gap: 6px; }
  .transfer-modes label { display: flex; align-items: flex-start; gap: 8px; padding: 8px 9px; border: 1px solid var(--border); border-radius: 8px; cursor: pointer; }
  .transfer-modes label.active { border-color: #d6b2a6; background: #fdf8f5; }
  .transfer-modes input { margin-top: 2px; accent-color: var(--accent); }
  .transfer-modes span { display: grid; gap: 2px; }
  .transfer-modes b { font-size: 11px; font-weight: 600; }
  .transfer-modes small { color: var(--faint); font-size: 9.5px; }
  .transfer-empty { margin: 4px 0; }
  .conn-list { display: flex; flex-direction: column; gap: 5px; }
  .conn-row { display: flex; align-items: center; gap: 10px; padding: 8px 10px; border: 1px solid var(--border); border-radius: 11px; cursor: pointer; transition: border-color .12s, background .12s; }
  .conn-row:hover { background: #faf9f6; }
  .conn-row.on { border-color: #cfc9ec; background: #f7f6ff; }
  .conn-row :global(.sm) { border-radius: 6px; }
  .conn-main { flex: 1; min-width: 0; } .conn-main b { display: block; font-size: 13.5px; } .conn-main small { display: block; color: var(--dim); font-size: 11px; }
  /* ★ 上面这条 display:block（0,1,1）会压过 .cs-os 的 inline-flex（0,1,0）：设置弹窗的连接行里
     发行版图标于是退回**行内基线对齐**——12px 的图标坐在 11px 文字的基线上，整个上蹿一截。
     这里把 flex 垂直居中赢回来（用 flex 而非 inline-flex：副标题本来就独占一行）。 */
  .conn-main small.cs-os { display: flex; align-items: center; }
  /* 技能包更新：设置行的一键升级按钮 + 切换器里的小圆点徽标 */
  .pack-upd { flex: none; border: none; background: var(--accent); color: #fff; font-size: 11px; font-weight: 550; padding: 3px 10px; border-radius: 7px; cursor: pointer; }
  .pack-upd:hover { background: var(--accent-h); }
  .pack-upd:disabled { opacity: .6; cursor: default; }
  .pack-dot { display: inline-block; width: 7px; height: 7px; border-radius: 50%; background: var(--accent); margin-left: 6px; vertical-align: 1px; }
  .icon-btn.sm { padding: 4px; border-radius: 7px; }
  .brain-row { display: flex; align-items: center; gap: 11px; padding: 0; }
  /* 状态点放进与 .icon-btn 同宽(27px)的居中盒，右缘、图标中心都与本地模型区的刷新图标对齐。 */
  .brain-dot { flex: none; width: 27px; display: inline-flex; align-items: center; justify-content: center; }
  .brain-ic { flex: none; width: 22px; height: 22px; display: inline-flex; align-items: center; justify-content: center; }
  .brain-main { flex: 1; min-width: 0; } .brain-main b { display: block; font-size: 13.5px; line-height: 1.15; } .brain-main small { display: block; color: var(--dim); font-size: 11px; line-height: 1.1; }
  /* 自定义模型：折叠管理器（对齐大脑名，缩进 33px = 图标 22 + gap 11） */
  /* 大脑列表：整列作为一个 sheet-body 子项，块间距自控（不吃 sheet-body 的 7px gap）。 */
  .brains-list { display: flex; flex-direction: column; gap: 14px; }
  /* 每个大脑（行 + 自定义模型）成一块，块内贴紧。 */
  .brain-block { display: flex; flex-direction: column; gap: 0; }
  /* 未安装行：一键安装挪到状态文字下方（缩进对齐 brain-main），复制小图标同行在旁 */
  .brain-install { display: flex; align-items: center; gap: 5px; margin: 3px 0 2px 33px; }
  .cust { margin: 0 0 0 33px; }
  .cust-head { display: inline-flex; align-items: center; gap: 5px; background: none; border: none; padding: 0; cursor: pointer; font: inherit; font-size: 11.5px; color: var(--dim); -webkit-appearance: none; appearance: none; }
  .cust-head:hover { color: var(--text); }
  .cust-chev { color: var(--faint); flex: none; transition: transform .12s; }
  .cust-chev:not(.open) { transform: rotate(-90deg); }
  .cust-n { min-width: 15px; height: 15px; padding: 0 4px; display: inline-flex; align-items: center; justify-content: center; background: var(--border); color: var(--dim); border-radius: 8px; font-size: 10px; font-weight: 600; }
  .cust-body { display: flex; flex-direction: column; gap: 5px; margin: 4px 0 4px; }
  .cust-chip { display: flex; align-items: center; gap: 6px; background: #f6f5f1; border: 1px solid var(--border); border-radius: 8px; padding: 4px 6px 4px 9px; }
  .cust-id { flex: 1; min-width: 0; font-family: ui-monospace, monospace; font-size: 11.5px; color: var(--text); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .cust-x { flex: none; background: none; border: none; color: var(--faint); font-size: 15px; line-height: 1; padding: 0 3px; border-radius: 5px; cursor: pointer; }
  .cust-x:hover { color: var(--err); background: #fff; }
  .cust-add { display: flex; gap: 6px; align-items: center; }
  .cust-add .tin { flex: 1; min-width: 0; width: auto; }
  .cust-add .btn { flex: none; }
  .hint { color: var(--dim); font-size: 12px; margin: 2px 0; line-height: 1.6; }
  .hint.mono { font-family: ui-monospace, monospace; font-size: 11px; color: var(--faint); background: #f6f5f1; padding: 5px 8px; border-radius: 6px; overflow-wrap: anywhere; }
  .hint.tos { color: var(--faint); margin-top: 12px; }
  .warn-text { color: var(--warn); }
  .dim { color: var(--dim); }
  .tin { width: 100%; }
  .row-end { display: flex; justify-content: flex-end; align-items: center; gap: 7px; margin-top: 2px; }

  /* 概览条容器（托管仪表盘 / 定时任务顶部共用）：裸化的安静统计行——无底无框，
     左缘与下方卡片列表对齐；各站例外收进「待审」的 hover 弹层（.ss-pop-menu）。趋势小柱在各站卡片数据行里 */
  .md-board { display: flex; flex-direction: column; gap: 3px; margin: 0 0 12px; padding: 2px 0 4px; }
  /* 数据条（可复用）：每段=数字(13px/600/正文色)+标签(11px faint)，段间 1px 细竖线，状态段带 6px 色点 */
  .stat-strip { display: flex; align-items: center; flex-wrap: wrap; row-gap: 4px; }
  .ss-seg { display: inline-flex; align-items: baseline; gap: 5px; min-width: 0; }
  .ss-seg + .ss-seg { margin-left: 18px; }
  .ss-num { font-size: 13px; font-weight: 600; color: var(--text); font-variant-numeric: tabular-nums; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 320px; }
  .ss-lbl { font-size: 11px; color: var(--faint); white-space: nowrap; }
  .ss-dot { width: 6px; height: 6px; border-radius: 50%; flex: none; align-self: center; }
  .ss-dot.ok { background: #3e9463; }
  .ss-dot.off { background: #b7b2a9; }
  .ss-dot.err { background: #c94f37; }
  .ss-dot.warn { background: #d9a400; }
  /* 全局共享 hover 气泡：挂到 body，真实测量后避让四边；高于弹窗，永远不被局部层级压住。 */
  :global(.ui-tip) { position: fixed; z-index: 1400; box-sizing: border-box; pointer-events: none; visibility: hidden; background: #26241f; color: #fff; font-size: 11px; line-height: 1.5; padding: 5px 9px; border-radius: 7px; width: max-content; max-width: min(320px, calc(100vw - 16px)); white-space: pre-line; overflow-wrap: anywhere; text-align: left; box-shadow: 0 5px 16px rgba(0, 0, 0, .18); animation: tipin .12s ease-out both; }
  .md-exc { display: flex; align-items: center; gap: 6px; width: fit-content; max-width: 100%; padding: 2px 6px; margin-left: -6px; border: none; background: none; border-radius: 7px; font-size: 12px; color: var(--dim); cursor: pointer; text-align: left; }
  .md-exc:hover { background: #efede7; }
  .md-exc-name { color: var(--text); font-weight: 500; }
  .md-exc-tag { flex: none; padding: 0 7px; border-radius: 999px; font-size: 10.5px; }
  .md-exc-tag.err { background: #f7e8e4; color: #a03c2b; }
  .md-exc-tag.warn { background: #fdf6e3; color: #9a6b00; }
  .md-exc-tag.off { background: #eee9df; color: var(--dim); }
  /* 「待审」悬停弹层：各站例外从常驻一行收进这里，移到「待审」上才展开。 */
  .ss-seg.ss-pop { position: relative; cursor: default; }
  .ss-seg.ss-pop:hover .ss-lbl { color: var(--dim); }
  .ss-pop-menu {
    display: flex; position: absolute; top: calc(100% + 5px); left: -8px; z-index: 60;
    min-width: 170px; flex-direction: column; gap: 1px; padding: 4px;
    background: #fff; border: 1px solid var(--border2); border-radius: 10px; box-shadow: 0 8px 26px rgba(30, 25, 15, .16);
    opacity: 0; visibility: hidden; transform: translateY(-2px); pointer-events: auto;
    transition: opacity .08s ease .12s, transform .08s ease .12s, visibility 0s linear .2s;
  }
  /* 扩大透明通道，并延迟收起；斜着移入菜单时也不会因短暂离开触发文字而消失。 */
  .ss-pop-menu::before { content: ''; position: absolute; left: -8px; right: -8px; top: -10px; height: 12px; }
  .ss-seg.ss-pop:hover .ss-pop-menu,
  .ss-seg.ss-pop:focus-within .ss-pop-menu {
    opacity: 1; visibility: visible; transform: translateY(0);
    transition-delay: 0s;
  }
  .ss-pop-menu .md-exc { width: 100%; margin-left: 0; }
  .mb-trend { display: inline-flex; align-items: flex-end; gap: 2px; height: 12px; font-size: 10.5px; color: var(--faint); }
  .mb-trend i { display: inline-block; width: 3px; background: var(--accent); border-radius: 1px; opacity: .7; }
  /* 周报归档列表与正文 */
  .rp-item { width: 100%; display: flex; align-items: center; justify-content: space-between; gap: 12px; padding: 8px 10px; border: none; background: none; border-radius: 8px; text-align: left; cursor: pointer; font: inherit; }
  .rp-item:hover { background: #f4f3ef; }
  .rp-date { flex: none; display: inline-flex; align-items: center; gap: 6px; font-size: 12.5px; font-weight: 500; color: var(--text); font-variant-numeric: tabular-nums; }
  .rp-mets { min-width: 0; font-size: 12px; color: var(--dim); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .rp-body { font-size: 13px; }

  /* 托管：卡片徽标 / 待审队列 / 计划编辑 / 向导边界说明 */
  .md-badge { margin-left: 8px; font-size: 10.5px; padding: 1px 7px; border-radius: 999px; background: #e8f0e4; color: #3c6b32; vertical-align: 1px; }
  .md-title-row { display: flex; align-items: center; flex-wrap: wrap; gap: 6px; min-width: 0; }
  .md-title-row > b { display: inline-flex; align-items: center; gap: 4px; min-width: 0; }
  .md-title-row > b :global(.site-fav) { flex: none; }
  .md-model-badge { display: inline-flex; align-items: center; margin-left: 1px; }
  .md-model-badge :global(.fx-trigger) { height: 22px; border: 1px solid var(--border2); border-radius: 999px; background: #f7f4ee; padding: 0 8px; font-size: 10.5px; }
  .md-model-badge :global(.fx-trigger:hover), .md-model-badge :global(.fx-trigger.open) { border-color: var(--accent); color: var(--accent); background: #fff; }
  .md-badge.off { background: #eee9df; color: var(--dim); }
  .md-task { font-size: 11.5px; padding: 1px 8px; border-radius: 999px; background: #f1efe9; color: var(--dim); margin-right: 6px; }
  .md-task.off { opacity: 0.55; text-decoration: line-through; }
  /* 通用文字链按钮（任务卡「查看对话/运行记录」、托管卡操作等）——此前从未定义,一直是系统默认灰凸样式 */
  .link { border: none; background: none; padding: 0; font: inherit; font-size: 12.5px; color: var(--accent); cursor: pointer; white-space: nowrap; }
  .link:hover { text-decoration: underline; }
  .md-actions { display: flex; align-items: center; flex-wrap: wrap; gap: 4px 6px; margin-top: 10px; padding-top: 9px; border-top: 1px solid var(--border, #ecebe6); }
  .md-actions .link { padding: 3px 9px; border-radius: 999px; font-size: 12px; color: var(--dim, #6b675f); }
  .md-actions .link:hover { background: #f1efe9; color: var(--text, #26241f); text-decoration: none; }
  .md-actions .link.md-primary { color: var(--accent); box-shadow: inset 0 0 0 1px #e6cabb; }
  /* 等级选择器伪装成头部徽标（bare 触发器 + 绿底胶囊） */
  .md-lv-badge { display: inline-block; margin-left: 8px; vertical-align: 1px; }
  .md-lv-badge :global(.dd) { width: auto; }
  .md-lv-badge :global(.dd-trigger.bare) { font-size: 10.5px; padding: 1px 7px; border-radius: 999px; background: #e8f0e4; color: #3c6b32; }
  .md-foot { display: flex; align-items: flex-start; gap: 5px; margin: 8px 0 0; font-size: 11px; color: var(--faint, #9b968c); }
  .md-foot svg { flex: none; margin-top: 3px; }
  .md-queue { margin-top: 8px; border: 1px solid var(--line, #e6e2d8); border-radius: 10px; padding: 4px 10px; background: #fbfaf7; }
  .md-row { display: flex; align-items: center; gap: 10px; padding: 7px 0; border-bottom: 1px dashed var(--line, #e6e2d8); }
  .md-row:last-child { border-bottom: none; }
  .md-title { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-size: 13px; }
  .md-sub { flex: none; color: var(--faint); font-size: 11.5px; }
  .md-btns { flex: none; display: flex; align-items: center; gap: 6px; }
  /* 预览：无边框无底的文字链（带 ↗），跟旁边两个实心按钮并排——次要动作退成链接 */
  .md-prev { flex: none; color: var(--dim); }
  .md-prev:hover { color: var(--accent); }
  .md-plan { margin-top: 8px; display: flex; flex-direction: column; gap: 8px; }
  .md-plan textarea { font-size: 12.5px; line-height: 1.6; }
  .md-genrow { display: flex; align-items: center; gap: 10px; margin: 6px 0 10px; }
  /* 向导按当前步骤内容自适应；只有第 3 步内容超过视口时才让正文滚动。 */
  .md-managed-wizard { height: fit-content; max-height: 88vh; overflow: hidden; }
  .md-managed-wizard .sheet-body { flex: 1 1 auto; min-height: 0; padding-bottom: 16px; }
  .md-managed-wizard .sheet-body > * { flex-shrink: 0; }
  .md-wizard-footer {
    flex: none;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 7px;
    padding: 12px 18px;
    border-top: 1px solid var(--border);
    background: var(--bg);
    box-shadow: 0 -8px 18px rgb(35 29 20 / 4%);
  }
  .md-managed-wizard .trow { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 12px; }
  .md-model-grid { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 12px; margin-bottom: 14px; }
  .md-model-card { min-width: 0; display: grid; align-content: start; gap: 8px; padding: 0; }
  .md-model-head { min-width: 0; min-height: 38px; display: flex; flex-direction: column; justify-content: center; gap: 2px; color: var(--text); }
  .md-model-head strong { font-size: 13px; line-height: 1.25; font-weight: 650; }
  .md-model-primary .md-model-head strong { font-size: 15px; font-weight: 700; }
  .md-model-head small { color: var(--faint); font-size: 10.5px; line-height: 1.35; font-weight: 400; }
  .md-model-head-fallback { flex-direction: row; align-items: center; justify-content: space-between; gap: 10px; }
  .md-model-head-fallback > span { min-width: 0; display: grid; gap: 2px; }
  .md-fallback-switch { flex: none; position: relative; width: 30px; height: 18px; padding: 0; border: 1px solid var(--line); border-radius: 999px; background: #e9e7e1; cursor: pointer; transition: background 140ms ease, border-color 140ms ease; }
  .md-fallback-switch > span { position: absolute; top: 2px; left: 2px; width: 12px; height: 12px; border-radius: 50%; background: #fff; box-shadow: 0 1px 2px rgb(35 29 20 / 18%); transition: transform 140ms ease; }
  .md-fallback-switch.active { border-color: var(--accent); background: var(--accent); }
  .md-fallback-switch.active > span { transform: translateX(12px); }
  .md-field-label { display: flex; align-items: baseline; gap: 7px; flex-wrap: wrap; color: var(--dim); line-height: 1.3; }
  .md-field-label b { font-size: 12px; font-weight: 600; }
  .md-field-label small { color: var(--faint); font-size: 10.5px; font-weight: 400; }
  .md-fallback-note { display: block; margin-top: -1px; color: var(--faint); font-size: 10.5px; line-height: 1.45; }
  .md-fallback-empty { width: 100%; height: var(--ctl-h); min-height: var(--ctl-h); margin: 0; padding: 0 10px; display: inline-flex; align-items: center; justify-content: center; gap: 6px; border: 1px dashed var(--line); border-radius: 8px; background: #faf9f6; color: var(--dim); font: inherit; font-size: 12px; cursor: pointer; }
  .md-fallback-empty:hover { color: var(--accent); border-color: #d7b2a6; background: #fff; }
  .md-prompts { flex: none; border: 1px solid var(--border2); border-radius: 10px; background: #fbfaf7; margin: 16px 0 12px; overflow: hidden; transition: border-color 140ms ease, background 140ms ease; }
  .md-prompts:hover { border-color: #d7cfc2; background: #fff; }
  .md-prompts[open] { background: #fff; }
  .md-prompts > summary { box-sizing: border-box; min-height: 58px; list-style: none; cursor: pointer; display: flex; align-items: center; gap: 11px; padding: 11px 14px; outline: none; }
  .md-prompts > summary:focus-visible { box-shadow: inset 0 0 0 2px color-mix(in srgb, var(--accent) 25%, transparent); }
